import { isPlatformBrowser } from '@angular/common';
import { Injectable, signal, inject, PLATFORM_ID } from '@angular/core';

const STORAGE_KEY = 'auth-token';

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly platformId = inject(PLATFORM_ID);
  private readonly tokenSignal = signal<string | null>(null);

  constructor() {
    if (!isPlatformBrowser(this.platformId)) {
      return;
    }

    const session = this.getSessionStorage();
    const local = this.getLocalStorage();

    let saved = session?.getItem(STORAGE_KEY) ?? null;
    if (!saved) {
      const legacy = local?.getItem(STORAGE_KEY) ?? null;
      if (legacy) {
        saved = legacy;
        session?.setItem(STORAGE_KEY, legacy);
        local?.removeItem(STORAGE_KEY);
      }
    }

    this.tokenSignal.set(saved);
  }

  get token() {
    return this.tokenSignal.asReadonly();
  }

  get isLoggedIn(): boolean {
    const t = this.tokenSignal();
    return !!t && t.trim().length > 0;
  }

  setToken(token: string) {
    const normalized = token.trim();
    this.getSessionStorage()?.setItem(STORAGE_KEY, normalized);
    this.tokenSignal.set(normalized);
  }

  logout(): void {
    this.clearToken();
  }

  clearToken() {
    this.getSessionStorage()?.removeItem(STORAGE_KEY);
    this.getLocalStorage()?.removeItem(STORAGE_KEY);
    this.tokenSignal.set(null);
  }

  private getSessionStorage(): Storage | null {
    if (!isPlatformBrowser(this.platformId)) {
      return null;
    }
    try {
      return globalThis?.sessionStorage ?? null;
    } catch {
      return null;
    }
  }

  private getLocalStorage(): Storage | null {
    if (!isPlatformBrowser(this.platformId)) {
      return null;
    }
    try {
      return globalThis?.localStorage ?? null;
    } catch {
      return null;
    }
  }
}

import { HttpInterceptorFn, HttpRequest, HttpHandlerFn } from '@angular/common/http';

import { environment } from '../../../environments/environment';

export const apiPrefixInterceptor: HttpInterceptorFn = (
  req: HttpRequest<unknown>,
  next: HttpHandlerFn,
) => {
  const apiBase = (environment?.baseUrl ?? '').trim();
  if (!apiBase) return next(req);
  const url = req.url ?? '';

  const isAbsolute = /^(https?:)?\/\//.test(url);
  if (!url || isAbsolute || url.startsWith(apiBase)) {
    return next(req);
  }

  const prefixed = apiBase.replace(/\/$/, '') + (url.startsWith('/') ? url : `/${url}`);
  const cloned = req.clone({ url: prefixed });
  return next(cloned);
};

import { HttpHandlerFn, HttpInterceptorFn, HttpRequest } from '@angular/common/http';
import { inject } from '@angular/core';

import { environment } from '../../../environments/environment';
import { AuthService } from '../auth/auth-service/auth.service';

const ABSOLUTE_URL_RE = /^(https?:)?\/\//i;

function shouldAttachToken(url: string): boolean {
  const normalized = url.trim();
  if (!normalized) {
    return false;
  }

  if (!ABSOLUTE_URL_RE.test(normalized)) {
    return true;
  }

  const apiBase = (environment?.baseUrl ?? '').trim();
  if (!apiBase) {
    return false;
  }

  try {
    const baseOrigin = new URL(apiBase).origin;
    const requestOrigin = new URL(normalized, apiBase).origin;
    return requestOrigin === baseOrigin;
  } catch {
    return false;
  }
}

export const authInterceptor: HttpInterceptorFn = (
  req: HttpRequest<unknown>,
  next: HttpHandlerFn,
) => {
  const auth = inject(AuthService);
  const token = auth.token();

  if (req.headers.has('Authorization')) {
    return next(req);
  }

  if (!token?.trim()) {
    return next(req);
  }

  if (!shouldAttachToken(req.url ?? '')) {
    return next(req);
  }

  const authReq = req.clone({
    setHeaders: {
      Authorization: `Bearer ${token.trim()}`,
    },
  });

  return next(authReq);
};

import { isPlatformBrowser } from '@angular/common';
import {
  HttpErrorResponse,
  HttpHandlerFn,
  HttpInterceptorFn,
  HttpRequest,
} from '@angular/common/http';
import { PLATFORM_ID, inject } from '@angular/core';
import { Router } from '@angular/router';
import { catchError, throwError, timer, retry } from 'rxjs';

import { I18nService } from '@app/shared/i18n/i18n.service';
import { ToastService } from '@app/shared/ui/toast/toast.service';
import { mapHttpError, type UiError } from '@app/shared/utils/error-mapper';

import { SKIP_GLOBAL_ERROR } from './http-context-tokens';
import { AuthService } from '../auth/auth-service/auth.service';

const MAX_RATE_LIMIT_RETRIES = 1;
const SKIP_GLOBAL_ERROR_HEADER = 'X-Skip-Global-Error';

function shouldSkipGlobalError(req: HttpRequest<unknown>): boolean {
  if (req.context.get(SKIP_GLOBAL_ERROR) === true) {
    return true;
  }

  const headerValue = req.headers.get(SKIP_GLOBAL_ERROR_HEADER);
  if (!headerValue) {
    return false;
  }

  const normalized = headerValue.trim().toLowerCase();
  return normalized === 'true' || normalized === '1';
}

function isIdempotentMethod(method: string): boolean {
  const upper = method.toUpperCase();
  return upper === 'GET' || upper === 'HEAD';
}

export const errorInterceptor: HttpInterceptorFn = (
  req: HttpRequest<unknown>,
  next: HttpHandlerFn,
) => {
  const platformId = inject(PLATFORM_ID);
  const isBrowser = isPlatformBrowser(platformId);
  const router = inject(Router);
  const auth = inject(AuthService);
  const toast = inject(ToastService);
  const i18n = inject(I18nService);
  const skipGlobal = shouldSkipGlobalError(req);
  const shouldRetry = isBrowser && !skipGlobal && isIdempotentMethod(req.method);

  const stream = shouldRetry
    ? next(req).pipe(
        retry({
          count: MAX_RATE_LIMIT_RETRIES,
          delay: (error, retryCount) => {
            const mapped = mapHttpError(error);
            if (mapped.kind === 'rate-limit') {
              const delayMs = mapped.retryAfterMs ?? Math.min(2000 * retryCount, 5000);
              const seconds = Math.max(1, Math.ceil(delayMs / 1000));
              toast.show(
                'info',
                i18n.translate('common.errors.rateLimitRetrying', { seconds }),
                delayMs + 500,
              );
              return timer(delayMs);
            }

            throw error;
          },
        }),
      )
    : next(req);

  return stream.pipe(
    catchError((error: unknown) => {
      const mapped = mapHttpError(error);
      const httpError =
        error instanceof HttpErrorResponse ? error : new HttpErrorResponse({ error, status: 0 });

      (httpError as HttpErrorResponse & { uiError?: UiError }).uiError = mapped;

      if (skipGlobal || !isBrowser) {
        return throwError(() => httpError);
      }

      switch (mapped.kind) {
        case 'unauthorized':
          auth.logout();
          toast.show('warning', i18n.translate(mapped.messageKey), 4000);
          router.navigate(['/login']).catch(() => {});
          break;
        case 'forbidden':
          toast.show('error', i18n.translate(mapped.messageKey), 4000);
          break;
        case 'validation':
          break;
        case 'rate-limit':
          toast.show('info', i18n.translate(mapped.messageKey), 4000);
          break;
        case 'network':
          toast.show('error', i18n.translate(mapped.messageKey), 4000);
          break;
        default:
          toast.show('error', i18n.translate(mapped.messageKey), 4000);
      }

      return throwError(() => httpError);
    }),
  );
};

import { isPlatformBrowser } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  DestroyRef,
  ElementRef,
  Injector,
  PLATFORM_ID,
  ViewChild,
  afterNextRender,
  computed,
  effect,
  inject,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormBuilder, ReactiveFormsModule, Validators, ValidationErrors } from '@angular/forms';
import { MatCardModule } from '@angular/material/card';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';

import { I18nService } from '@app/shared/i18n/i18n.service';
import { TranslatePipe } from '@app/shared/i18n/translate.pipe';
import { AlertComponent } from '@app/shared/ui/alert/alert.component';
import { ButtonComponent } from '@app/shared/ui/button/button.component';

import { LoginFacadeService } from './services/login-facade.service';
import { LoginUiService } from './services/login-ui.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    MatCardModule,
    MatFormFieldModule,
    MatInputModule,
    ButtonComponent,
    MatIconModule,
    AlertComponent,
    TranslatePipe,
  ],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class Login {
  private readonly fb = inject(FormBuilder);
  private readonly loginFacade = inject(LoginFacadeService);
  private readonly loginUi = inject(LoginUiService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly i18n = inject(I18nService);
  private readonly platformId = inject(PLATFORM_ID);
  private readonly injector = inject(Injector);
  private readonly isBrowser = isPlatformBrowser(this.platformId);

  readonly loading = signal(false);
  private readonly apiErrorMessage = signal<string | null>(null);
  readonly submissionMessage = signal<string | null>(null);
  private readonly attemptedSubmit = signal(false);
  readonly tokenErrorId = 'token-error';
  readonly formErrorId = 'login-form-error';

  @ViewChild('tokenInput') private readonly tokenInput?: ElementRef<HTMLInputElement>;
  @ViewChild('formAlert', { read: ElementRef })
  private readonly formAlert?: ElementRef<HTMLElement>;

  readonly form = this.fb.nonNullable.group({
    token: this.fb.nonNullable.control('', {
      validators: [Validators.required, Validators.minLength(8)],
    }),
  });

  readonly tokenControl = this.form.controls.token;

  readonly tokenErrorMessage = computed(() => {
    const control = this.tokenControl;
    if (!(control.touched || control.dirty || this.attemptedSubmit())) {
      return null;
    }

    if (control.hasError('required')) {
      return this.i18n.translate('login.errors.required');
    }

    const minlength = control.getError('minlength');
    if (minlength) {
      return this.i18n.translate('login.errors.minLength', { count: minlength.requiredLength });
    }

    if (control.hasError('api')) {
      return this.apiErrorMessage();
    }

    return null;
  });

  readonly tokenDescribedBy = computed(() => {
    const ids: string[] = [];
    if (this.tokenErrorMessage()) {
      ids.push(this.tokenErrorId);
    }
    if (this.submissionMessage()) {
      ids.push(this.formErrorId);
    }
    return ids.length ? ids.join(' ') : null;
  });

  readonly showTokenInvalidState = computed(
    () =>
      this.tokenControl.invalid &&
      (this.tokenControl.touched || this.tokenControl.dirty || this.attemptedSubmit()),
  );

  constructor() {
    effect(() => {
      const isLoading = this.loading();
      if (isLoading && this.tokenControl.enabled) {
        this.tokenControl.disable({ emitEvent: false });
      } else if (!isLoading && this.tokenControl.disabled) {
        this.tokenControl.enable({ emitEvent: false });
      }
    });

    this.tokenControl.valueChanges.pipe(takeUntilDestroyed(this.destroyRef)).subscribe(() => {
      if (this.tokenControl.hasError('api')) {
        const existing: ValidationErrors = (this.tokenControl.errors ?? {}) as ValidationErrors;
        const rest = Object.fromEntries(
          Object.entries(existing).filter(([k]) => k !== 'api'),
        ) as ValidationErrors;
        this.tokenControl.setErrors(Object.keys(rest).length ? rest : null);
      }
      if (this.apiErrorMessage()) {
        this.apiErrorMessage.set(null);
      }
      if (this.submissionMessage()) {
        this.submissionMessage.set(null);
      }
    });
  }

  onSubmit(): void {
    if (this.loading()) {
      return;
    }

    this.attemptedSubmit.set(true);
    this.apiErrorMessage.set(null);
    this.submissionMessage.set(null);

    if (this.form.invalid) {
      this.form.markAllAsTouched();
      this.focusTokenInput();
      return;
    }

    this.loading.set(true);

    this.loginFacade
      .login(this.tokenControl.value)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((result) => {
        this.loading.set(false);

        if (!result.success) {
          const message =
            result.message ?? this.loginUi.getErrorMessage('login.errors.unableToVerify');

          if (result.code === 'unauthorized' || result.code === 'empty') {
            const existingErrors = this.tokenControl.errors ?? {};
            this.tokenControl.setErrors({ ...existingErrors, api: true });
            this.tokenControl.markAsTouched();
            this.tokenControl.markAsDirty();
            this.apiErrorMessage.set(message);
            this.loginUi.showError(message);
            this.focusTokenInput();
            return;
          }

          this.submissionMessage.set(message);
          this.loginUi.showError(message);
          this.focusFormAlert();
          return;
        }

        this.form.reset({ token: '' });
        this.attemptedSubmit.set(false);
      });
  }

  openTokenHelp(): void {
    this.loginUi.openTokenHelp();
  }

  private focusTokenInput(): void {
    if (!this.isBrowser) return;
    afterNextRender(() => this.tokenInput?.nativeElement?.focus(), { injector: this.injector });
  }

  private focusFormAlert(): void {
    if (!this.isBrowser) return;
    afterNextRender(() => this.formAlert?.nativeElement?.focus(), { injector: this.injector });
  }
}

import { CommonModule } from '@angular/common';
import { ChangeDetectionStrategy, Component, computed, inject, input, output } from '@angular/core';
import { MatCardModule } from '@angular/material/card';
import { MatIconModule } from '@angular/material/icon';

import { I18nService } from '@app/shared/i18n/i18n.service';
import { TranslatePipe } from '@app/shared/i18n/translate.pipe';
import { ButtonComponent } from '@app/shared/ui/button/button.component';

import type { Post } from '@/app/shared/models/post';

@Component({
  selector: 'app-post-card',
  standalone: true,
  imports: [CommonModule, MatIconModule, MatCardModule, ButtonComponent, TranslatePipe],
  templateUrl: './post-card.component.html',
  styleUrls: ['./post-card.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PostCardComponent {
  private readonly i18n = inject(I18nService);

  readonly post = input.required<Post>();
  readonly isDeleting = input(false);
  readonly authorName = input<string | null>(null);
  readonly commentsPreviewCount = input<number | null | undefined>(undefined);
  readonly allowManage = input(true);
  readonly author = computed(() => {
    const provided = this.authorName();
    if (provided) return provided;

    const current = this.post();
    if (!current) {
      return this.i18n.translate('postCard.unknownAuthor');
    }

    const fallback = this.i18n.translate('userDetail.avatarFallback');
    return `${fallback} #${current.user_id}`;
  });

  readonly delete = output<void>();
  readonly edit = output<void>();
  readonly viewAuthor = output<number>();
  readonly viewComments = output<Post>();

  get commentCount(): number {
    return this.commentsPreviewCount() ?? this.post().comments_count ?? 0;
  }

  isExpanded = false;

  shouldTruncate(): boolean {
    const body = this.post().body || '';
    return body.length > 220;
  }

  previewText(): string {
    return this.preview(undefined, 220);
  }

  preview(text?: string, max = 220): string {
    const body = text ?? this.post().body ?? '';
    if (body.length <= max) {
      return body;
    }

    const truncated = body.slice(0, max);
    return truncated.replace(/\s+\S*$/, '') + '...';
  }

  toggleExpansion(): void {
    this.isExpanded = !this.isExpanded;
  }

  bodyId(): string {
    const current = this.post();
    return `post-body-${current?.id ?? 'unknown'}`;
  }

  onEditClick(): void {
    this.edit.emit();
  }

  onAuthorClick(): void {
    const current = this.post();
    if (current) {
      this.viewAuthor.emit(current.user_id);
    }
  }

  onViewComments(): void {
    const current = this.post();
    if (current) {
      this.viewComments.emit(current);
    }
  }
}

import { DialogRef, DIALOG_DATA } from '@angular/cdk/dialog';
import { CommonModule } from '@angular/common';
import { ChangeDetectionStrategy, Component, computed, inject } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';

import { I18nService } from '@app/shared/i18n/i18n.service';
import { TranslatePipe } from '@app/shared/i18n/translate.pipe';
import { ButtonComponent } from '@app/shared/ui/button/button.component';
import { CommentFormComponent } from '@app/shared/ui/comment-form/comment-form.component';

import type { Comment, Post } from '@/app/shared/models/post';
import { CommentsFacadeService } from '@/app/shared/services/comments/comments-facade.service';

import { PostCommentsComponent } from '../post-comments/post-comments.component';

interface PostCommentsDialogData {
  post: Post;
  authorName?: string | null;
}

@Component({
  selector: 'app-post-comments-dialog',
  standalone: true,
  imports: [
    CommonModule,
    MatIconModule,
    ButtonComponent,
    TranslatePipe,
    PostCommentsComponent,
    CommentFormComponent,
  ],
  templateUrl: './post-comments-dialog.component.html',
  styleUrls: ['./post-comments-dialog.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PostCommentsDialogComponent {
  private readonly commentsFacade = inject(CommentsFacadeService);
  private readonly i18n = inject(I18nService);
  private readonly dialogRef = inject(DialogRef<PostCommentsDialogComponent>);
  readonly data = inject(DIALOG_DATA) as PostCommentsDialogData;

  readonly comments = computed(() => this.commentsFacade.comments()[this.data.post.id] ?? []);
  readonly loading = computed(() => Boolean(this.commentsFacade.loading()[this.data.post.id]));
  readonly authorName = computed(() => {
    const provided = this.data.authorName?.trim();
    if (provided) return provided;

    const fallback = this.i18n.translate('userDetail.avatarFallback');
    const id = this.data.post.user_id ?? 'unknown';
    return `${fallback} #${id}`;
  });

  readonly ariaLabel = computed(() =>
    this.i18n.translate('postComments.dialogAria', { title: this.data.post.title ?? '' }),
  );

  readonly labelText = computed(() => this.i18n.translate('postComments.dialogLabel'));

  close(): void {
    this.dialogRef.close();
  }

  onCommentCreated(comment: Comment): void {
    this.commentsFacade.applyCreated(this.data.post.id, comment);
  }

  onCommentUpdated(comment: Comment): void {
    this.commentsFacade.applyUpdated(this.data.post.id, comment);
  }

  onCommentDeleted(commentId: number): void {
    this.commentsFacade.applyDeleted(this.data.post.id, commentId);
  }
}

import { Dialog } from '@angular/cdk/dialog';
import { CommonModule } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  DestroyRef,
  effect,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { MatIconModule } from '@angular/material/icon';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { tap, take } from 'rxjs';

import { I18nService } from '@app/shared/i18n/i18n.service';
import { TranslatePipe } from '@app/shared/i18n/translate.pipe';

import type { DeleteConfirmData } from '@/app/shared/models/dialog';
import type { Comment as ModelComment } from '@/app/shared/models/post';
import { CommentsFacadeService } from '@/app/shared/services/comments/comments-facade.service';
import { UiOverlayService } from '@/app/shared/services/ui-overlay/ui-overlay.service';
import { AlertComponent } from '@/app/shared/ui/alert/alert.component';
import { ButtonComponent } from '@/app/shared/ui/button/button.component';
import { DeleteConfirmComponent } from '@/app/shared/ui/dialog/delete-confirm.component';
import { ToastService } from '@/app/shared/ui/toast/toast.service';

@Component({
  standalone: true,
  selector: 'app-post-comments',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonComponent,
    AlertComponent,
    MatIconModule,
    MatProgressBarModule,
    TranslatePipe,
  ],
  templateUrl: './post-comments.component.html',
  styleUrls: ['./post-comments.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PostCommentsComponent {
  readonly comments = input<ModelComment[]>([]);
  readonly loading = input(false);
  readonly postId = input.required<number>();

  readonly commentCreated = output<ModelComment>();
  readonly commentUpdated = output<ModelComment>();
  readonly commentDeleted = output<number>();

  private readonly fb = inject(FormBuilder);
  private readonly commentsFacade = inject(CommentsFacadeService);
  private readonly toast = inject(ToastService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly i18n = inject(I18nService);
  private readonly overlays = inject(UiOverlayService);

  private readonly dialog = inject(Dialog);
  readonly deletingId = signal<number | null>(null);
  deleteComment(comment: ModelComment): void {
    const data: DeleteConfirmData = {
      title: this.i18n.translate('postComments.deleteConfirm.title'),
      message: this.i18n.translate('postComments.deleteConfirm.message'),
      confirmText: this.i18n.translate('common.actions.delete'),
      cancelText: this.i18n.translate('common.actions.cancel'),
      inProgressText: this.i18n.translate('postComments.deleteConfirm.inProgress'),
      errorMessage: this.i18n.translate('postComments.deleteConfirm.errorMessage'),
      confirmAction: () => {
        this.deletingId.set(comment.id);
        return this.commentsFacade.deleteComment(comment.id).pipe(
          tap({
            next: () => {
              this.deletingId.set(null);
              this.commentDeleted.emit(comment.id);
              this.toast.show('success', this.i18n.translate('postComments.toast.deleted'));
            },
            error: (err) => {
              this.deletingId.set(null);
              console.error('Failed to delete comment', err);
              const message =
                err?.status === 429
                  ? this.i18n.translate('postComments.errors.rateLimit')
                  : this.i18n.translate('postComments.deleteConfirm.errorMessage');
              this.toast.show('error', message);
              throw err;
            },
          }),
        );
      },
    };
    const ref = this.dialog.open(DeleteConfirmComponent, {
      width: '400px',
      maxWidth: '90vw',
      backdropClass: 'app-dialog-overlay',
      panelClass: ['app-dialog-panel', 'app-dialog--sm'],
      ariaLabel: this.i18n.translate('postComments.deleteConfirm.title'),
      autoFocus: true,
      restoreFocus: true,
      data,
    });
    this.overlays.activate({
      key: 'comment-delete-confirm',
      close: () => ref.close(),
      blockGlobalControls: true,
    });
    ref.closed.pipe(take(1)).subscribe(() => {
      this.overlays.release('comment-delete-confirm');
    });
  }

  readonly editingId = signal<number | null>(null);
  readonly submittingEdit = signal(false);
  readonly editError = signal<string | null>(null);

  readonly editForm = this.fb.nonNullable.group({
    body: this.fb.nonNullable.control('', [Validators.required, Validators.minLength(5)]),
  });

  constructor() {
    effect(() => {
      const disable = this.submittingEdit();
      const control = this.editForm.controls.body;
      if (disable && control.enabled) {
        control.disable({ emitEvent: false });
      } else if (!disable && control.disabled) {
        control.enable({ emitEvent: false });
      }
    });
  }

  startEdit(comment: ModelComment): void {
    this.editingId.set(comment.id);
    this.editError.set(null);
    this.editForm.reset({ body: comment.body });
  }

  cancelEdit(): void {
    this.editingId.set(null);
    this.editError.set(null);
    this.editForm.reset();
  }

  saveEdit(comment: ModelComment): void {
    if (this.editForm.invalid || this.submittingEdit()) {
      this.editForm.markAllAsTouched();
      return;
    }

    const trimmed = this.editForm.controls.body.value.trim();
    if (!trimmed || trimmed === comment.body) {
      this.cancelEdit();
      return;
    }

    this.submittingEdit.set(true);
    this.editError.set(null);

    this.commentsFacade
      .updateComment(comment.id, { body: trimmed })
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (updated) => {
          if (updated) {
            this.commentUpdated.emit(updated);
          }
          this.toast.show('success', this.i18n.translate('postComments.toast.updated'));
          this.submittingEdit.set(false);
          this.cancelEdit();
        },
        error: (err) => {
          console.error('Failed to update comment', err);
          this.submittingEdit.set(false);
          if (err?.status === 422) {
            this.editError.set(this.i18n.translate('postComments.errors.editInvalid'));
          } else if (err?.status === 429) {
            this.toast.show('error', this.i18n.translate('postComments.errors.rateLimit'));
          } else {
            this.toast.show('error', this.i18n.translate('postComments.toast.updateFailed'));
          }
        },
      });
  }

  trackByCommentId(_index: number, comment: ModelComment): number {
    return comment.id;
  }

  onCommentCreated(comment: ModelComment): void {
    this.commentCreated.emit(comment);
  }
}

import { DialogRef, DIALOG_DATA } from '@angular/cdk/dialog';
import {
  ChangeDetectionStrategy,
  Component,
  DestroyRef,
  computed,
  effect,
  inject,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { MatSelectModule } from '@angular/material/select';

import { AutoFocusDirective } from '@app/shared/directives/auto-focus.directive';
import { I18nService } from '@app/shared/i18n/i18n.service';
import { TranslatePipe } from '@app/shared/i18n/translate.pipe';
import { AlertComponent } from '@app/shared/ui/alert/alert.component';
import { ButtonComponent } from '@app/shared/ui/button/button.component';
import { SelectComponent } from '@app/shared/ui/select/select.component';
import { ToastService } from '@app/shared/ui/toast/toast.service';

import { PostsApiService } from '@/app/shared/data-access/posts/posts-api.service';
import type { CreatePost, Post, UpdatePost } from '@/app/shared/models/post';
import type { User } from '@/app/shared/models/user';
import { UsersLookupService } from '@/app/shared/services/users/users-lookup.service';

interface PostFormDialogData {
  users?: User[];
  post?: Post;
}

interface PostFormResult {
  status: 'created' | 'updated';
  post: Post;
}

@Component({
  selector: 'app-post-form',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    AutoFocusDirective,
    ButtonComponent,
    AlertComponent,
    SelectComponent,
    MatFormFieldModule,
    MatInputModule,
    MatSelectModule,
    MatIconModule,
    MatProgressSpinnerModule,
    TranslatePipe,
  ],
  templateUrl: './post-form.component.html',
  styleUrls: ['./post-form.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PostForm {
  private readonly fb = inject(FormBuilder);
  private readonly postsApi = inject(PostsApiService);
  private readonly usersLookup = inject(UsersLookupService);
  private readonly dialogRef = inject(DialogRef<PostFormResult | 'cancel'>);
  private readonly destroyRef = inject(DestroyRef);
  private readonly dialogData = inject<PostFormDialogData | null>(DIALOG_DATA, { optional: true });
  private readonly i18n = inject(I18nService);

  readonly users = computed(() => this.usersLookup.users());
  private readonly editablePost = signal<Post | null>(this.dialogData?.post ?? null);
  readonly loadingUsers = computed(() => this.usersLookup.isLoading());
  readonly loadError = signal<string | null>(null);
  readonly submitting = signal(false);
  private readonly toast = inject(ToastService);

  private readonly userIdControl = this.fb.nonNullable.control(0, [
    Validators.required,
    Validators.min(1),
  ]);
  private readonly titleControl = this.fb.nonNullable.control('', [
    Validators.required,
    Validators.minLength(5),
  ]);
  private readonly bodyControl = this.fb.nonNullable.control('', [
    Validators.required,
    Validators.minLength(20),
  ]);

  readonly form = this.fb.nonNullable.group({
    userId: this.userIdControl,
    title: this.titleControl,
    body: this.bodyControl,
  });

  readonly isEdit = computed(() => this.editablePost() !== null);
  readonly dialogTitle = computed(() => {
    return this.isEdit()
      ? this.i18n.translate('postForm.titleEdit')
      : this.i18n.translate('postForm.titleNew');
  });

  readonly dialogSubtitle = computed(() => {
    return this.isEdit()
      ? this.i18n.translate('postForm.subtitleEdit')
      : this.i18n.translate('postForm.subtitleNew');
  });

  readonly submitLabel = computed(() => {
    if (this.submitting()) return this.i18n.translate('postForm.buttons.saving');
    if (this.isEdit()) return this.i18n.translate('postForm.buttons.update');
    return this.i18n.translate('postForm.buttons.create');
  });

  readonly userOptions = computed(() =>
    this.users().map((user) => ({
      value: user.id,
      label: `${user.name} (ID ${user.id})`,
    })),
  );

  constructor() {
    const prefetchedUsers = this.dialogData?.users ?? [];
    if (prefetchedUsers.length) {
      this.usersLookup.seed(prefetchedUsers);
    }

    this.loadUsers();

    const post = this.editablePost();
    if (post) {
      this.form.patchValue({
        userId: post.user_id,
        title: post.title,
        body: post.body,
      });

      if (!this.users().some((user) => user.id === post.user_id)) {
        this.usersLookup
          .ensureUserInCache(post.user_id)
          .pipe(takeUntilDestroyed(this.destroyRef))
          .subscribe({
            error: () => {},
          });
      }
    }

    effect(() => {
      const disableUser = this.submitting() || this.loadingUsers() || this.users().length === 0;
      if (disableUser && this.userIdControl.enabled) {
        this.userIdControl.disable({ emitEvent: false });
      } else if (!disableUser && this.userIdControl.disabled) {
        this.userIdControl.enable({ emitEvent: false });
      }
    });

    effect(() => {
      const disableFields = this.submitting();
      const controls = [this.titleControl, this.bodyControl];
      for (const control of controls) {
        if (disableFields && control.enabled) {
          control.disable({ emitEvent: false });
        } else if (!disableFields && control.disabled) {
          control.enable({ emitEvent: false });
        }
      }
    });
  }

  private loadUsers(force = false): void {
    this.loadError.set(null);
    this.usersLookup
      .ensureUsersLoaded({ force })
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        error: (err) => {
          console.error('Failed to load users for post form:', err);
          this.loadError.set(this.i18n.translate('postForm.errors.unableToLoadUsers'));
        },
      });
  }

  get userIdInvalid(): boolean {
    const control = this.userIdControl;
    return control.touched && control.invalid;
  }

  get titleInvalid(): boolean {
    const control = this.titleControl;
    return control.touched && control.invalid;
  }

  get bodyInvalid(): boolean {
    const control = this.bodyControl;
    return control.touched && control.invalid;
  }

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    const payload: CreatePost = {
      user_id: this.userIdControl.value,
      title: this.titleControl.value.trim(),
      body: this.bodyControl.value.trim(),
    };

    this.submitting.set(true);
    this.dialogRef.disableClose = true;

    const existing = this.editablePost();
    const request$ = existing
      ? this.postsApi.update(existing.id, payload as UpdatePost)
      : this.postsApi.create(payload);

    request$.pipe(takeUntilDestroyed(this.destroyRef)).subscribe({
      next: (post) => {
        this.submitting.set(false);
        this.dialogRef.disableClose = false;
        this.dialogRef.close({
          status: existing ? 'updated' : 'created',
          post,
        });
      },
      error: (err) => {
        console.error('Failed to create post:', err);
        this.submitting.set(false);
        this.dialogRef.disableClose = false;
        const status = err?.status;
        if (status === 422) {
          this.titleControl.setErrors({ api: true });
        } else if (status === 429) {
          this.toast.show('error', this.i18n.translate('postForm.errors.rateLimit'));
        } else {
          this.toast.show('error', this.i18n.translate('postForm.errors.saveFailed'));
        }
      },
    });
  }

  retryLoadUsers(): void {
    this.loadUsers(true);
  }

  cancel(): void {
    this.dialogRef.close('cancel');
  }
}

