interface PostsState {
  posts: Post[];
  postEntities: Record<number, Post>;
  pagination: PaginationMeta | null;
  deletingId: number | null;
  loading: boolean;
  error: string | null;
  page: number;
  perPage: number;
  reloadToken: number;
}

const defaultState: PostsState = {
  posts: [],
  postEntities: {},
  pagination: null,
  deletingId: null,
  loading: false,
  error: null,
  page: 1,
  perPage: 10,
  reloadToken: 0,
};

export const PostsStoreAdapter = signalStore(
  withState<PostsState>(defaultState),

  withComputed((store) => {
    const filtersService = inject(PostsFiltersService);
    const commentsFacade = inject(CommentsFacadeService);
    const usersLookup = inject(UsersLookupService);

    return {
      filters: computed(() => filtersService.filters()),
      queryCriteria: computed<QueryCriteria>(() => {
        const filters = filtersService.filters();
        return {
          page: store.page(),
          perPage: store.perPage(),
          title: filters.title ?? undefined,
          userId: filters.userId ?? undefined,
          reload: store.reloadToken(),
        };
      }),
      hasPagination: computed(() => {
        const meta = store.pagination();
        return Boolean(meta && meta.pages > 1);
      }),
      currentPage: computed(() => store.pagination()?.page ?? store.page()),
      totalPages: computed(() => store.pagination()?.pages ?? 1),
      currentPerPage: computed(() => store.pagination()?.limit ?? store.perPage()),
      totalPosts: computed(() => store.pagination()?.total ?? store.posts().length),
      commentsMap: computed(() => commentsFacade.comments()),
      commentsLoading: computed(() => commentsFacade.loading()),
      commentsCountMap: computed(() => commentsFacade.counts()),
      userOptions: computed(() => usersLookup.users()),
      userLookup: computed(() =>
        usersLookup.users().reduce<Record<number, string>>((acc, user) => {
          acc[user.id] = user.name ?? `User #${user.id}`;
          return acc;
        }, {}),
      ),
    };
  }),

  withMethods((store) => {
    const postsApi = inject(PostsApiService);
    const commentsFacade = inject(CommentsFacadeService);
    const usersLookup = inject(UsersLookupService);
    const notifications = inject(NotificationsService);
    const i18n = inject(I18nService);
    const destroyRef = inject(DestroyRef);
    const platformId = inject(PLATFORM_ID);
    const filtersService = inject(PostsFiltersService);
    const queryCache = inject(QueryCacheService);
    const postsStoreConfig = inject(POSTS_STORE_CONFIG);
    const pagination =
      inject<PaginationConfig | null>(PAGINATION_CONFIG, { optional: true }) ??
      DEFAULT_PAGINATION_CONFIG;
    const isBrowser = isPlatformBrowser(platformId);
    const POSTS_CACHE_TTL_MS = 30_000;

    const invalidatePostsCache = (): void => {
      queryCache.invalidate('posts|');
    };

    const computePaginationAfterRemoval = (state: PostsState): PaginationMeta | null => {
      if (!state.pagination) return null;
      const nextTotal = Math.max(state.pagination.total - 1, 0);
      const limit = state.pagination.limit || store.perPage();
      return {
        ...state.pagination,
        total: nextTotal,
        pages: Math.max(1, Math.ceil(nextTotal / limit)),
      };
    };

    const removePostFromState = (state: PostsState, id: number) => {
      const nextEntities = { ...state.postEntities };
      delete nextEntities[id];

      return {
        deletingId: null,
        posts: state.posts.filter((item) => item.id !== id),
        postEntities: nextEntities,
        pagination: computePaginationAfterRemoval(state),
      };
    };

    const applyPostsResult = (
      result: { items?: Post[]; pagination?: PaginationMeta | null } | null,
    ) => {
      const list = result?.items ?? [];
      const entities = list.reduce<Record<number, Post>>((acc, post) => {
        acc[post.id] = post;
        return acc;
      }, {});
      patchState(store, {
        loading: false,
        posts: list,
        postEntities: entities,
        pagination: result?.pagination ?? null,
      });
    };

    const handleListError = (err: unknown) => {
      console.error('Failed to load posts:', err);
      const message = notifications.showHttpError(err, i18n.translate('posts.loadError'));
      patchState(store, { error: message, loading: false });
      return of(null);
    };

    const fetchPosts = (params: QueryCriteria) => {
      const { page, perPage, title, userId, reload } = params;
      const cacheKey = `posts|${page}|${perPage}|${title ?? ''}|${userId ?? ''}|${reload ?? 0}`;

      const cached = queryCache.get<{ items: Post[]; pagination: PaginationMeta | null }>(cacheKey);

      if (cached) {
        applyPostsResult(cached);
        return of(cached);
      }

      return postsApi.list({ page, perPage, title, userId }).pipe(
        map((result) => ({
          items: result?.items ?? [],
          pagination: result?.pagination ?? null,
        })),
        tap((toCache) => {
          queryCache.set(cacheKey, toCache, { ttl: POSTS_CACHE_TTL_MS });
          applyPostsResult(toCache);
          prefetchCommentCounts(toCache.items);
        }),
        catchError((err) => handleListError(err)),
      );
    };

    const shouldGoToPreviousPage = () =>
      store.posts().length <= 1 && store.currentPage() > 1 && store.totalPages() > 1;

    const immediateListRequests$ = new Subject<QueryCriteria>();
    const debouncedListRequests$ = new Subject<QueryCriteria>();

    patchState(store, {
      page: pagination.defaultPage,
      perPage: pagination.defaultPerPage,
    });

    const searchForm = signal(filtersService.form);
    const perPageOptions = signal([...pagination.perPageOptions]);

    initializePostsStream();
    bootstrapUserOptions();
    syncPaginationOnFilterChange();

    const performDeletePost = (post: Post | null | undefined) => {
      const postId = post?.id;
      if (!Number.isFinite(postId) || postId === null || postId === undefined) {
        patchState(store, { deletingId: null });
        return throwError(() => new Error('Invalid post'));
      }

      const shouldGoPrev = shouldGoToPreviousPage();

      patchState(store, { deletingId: postId });

      return postsApi.delete(postId).pipe(
        tap({
          next: () => {
            patchState(store, (state) => removePostFromState(state, postId));
            invalidatePostsCache();
            patchState(store, (state) => ({ reloadToken: state.reloadToken + 1 }));
            notifications.showSuccess(i18n.translate('posts.delete.success'));
            if (shouldGoPrev) {
              patchState(store, (state) => ({ page: Math.max(state.page - 1, 1) }));
              requestImmediateListReload();
            }
          },
          error: (err) => {
            console.error('Failed to delete post:', err);
            patchState(store, { deletingId: null });
          },
        }),
        catchError((err) => {
          const message = notifications.showHttpError(err, i18n.translate('posts.delete.error'));
          return throwError(() => new Error(message));
        }),
      );
    };

    return {
      searchForm,
      perPageOptions,

      initializePaging(page: number, perPage: number): void {
        const sanitizedPerPage = Math.max(1, perPage);
        const sanitizedPage = Math.max(1, page);
        patchState(store, { perPage: sanitizedPerPage, page: sanitizedPage });
        requestImmediateListReload();
      },

      setPage(page: number): void {
        const configuredTotalPages = store.pagination()?.pages;
        const next =
          typeof configuredTotalPages === 'number' && Number.isFinite(configuredTotalPages)
            ? Math.max(1, Math.min(page, Math.max(1, configuredTotalPages)))
            : Math.max(1, page);
        patchState(store, { page: next });
        requestImmediateListReload();
      },

      refresh(): void {
        invalidatePostsCache();
        patchState(store, (state) => ({ reloadToken: state.reloadToken + 1 }));
        requestImmediateListReload();
      },

      resetFilters(): void {
        filtersService.reset();
        patchState(store, {
          page: pagination.defaultPage,
          perPage: pagination.defaultPerPage,
        });
        requestDebouncedListReload();
      },

      deletePost(post: Post): void {
        performDeletePost(post)
          .pipe(takeUntilDestroyed(destroyRef))
          .subscribe({
            next: () => void 0,
            error: () => void 0,
          });
      },

      deletePostRequest(post: Post) {
        return performDeletePost(post);
      },

      onPostUpdated(updated: Post): void {
        patchState(store, (state) => ({
          posts: state.posts.map((post) => (post.id === updated.id ? updated : post)),
          postEntities: {
            ...state.postEntities,
            [updated.id]: updated,
          },
        }));
        invalidatePostsCache();
      },

      changePerPage(perPage: number): void {
        const sanitized = Math.max(1, perPage);
        if (sanitized === store.perPage()) return;
        const nextPage = normalizePage(1, pagination.defaultPage);
        patchState(store, { perPage: sanitized, page: nextPage });
        requestImmediateListReload();
      },

      setFilters(filters: PostFilters): void {
        filtersService.patch(filters);
        requestDebouncedListReload();
      },
    };

    function initializePostsStream(): void {
      if (!isBrowser) {
        patchState(store, { loading: false });
        return;
      }

      const debounceMs = Math.max(0, postsStoreConfig.debounceMs);

      immediateListRequests$
        .pipe(
          startWith(store.queryCriteria()),
          distinctUntilChanged(
            (a, b) =>
              a.page === b.page &&
              a.perPage === b.perPage &&
              a.title === b.title &&
              a.userId === b.userId &&
              a.reload === b.reload,
          ),
          switchMap((criteria) => {
            patchState(store, { loading: true, error: null });
            return fetchPosts(criteria);
          }),
          takeUntilDestroyed(destroyRef),
        )
        .subscribe({ next: () => void 0, error: () => void 0 });

      debouncedListRequests$
        .pipe(
          debounceTime(debounceMs),
          distinctUntilChanged(
            (a, b) =>
              a.page === b.page &&
              a.perPage === b.perPage &&
              a.title === b.title &&
              a.userId === b.userId &&
              a.reload === b.reload,
          ),
          switchMap((criteria) => {
            patchState(store, { loading: true, error: null });
            return fetchPosts(criteria);
          }),
          takeUntilDestroyed(destroyRef),
        )
        .subscribe({ next: () => void 0, error: () => void 0 });
    }

    function requestImmediateListReload(): void {
      if (!isBrowser) return;
      immediateListRequests$.next(store.queryCriteria());
    }

    function requestDebouncedListReload(): void {
      if (!isBrowser) return;
      debouncedListRequests$.next(store.queryCriteria());
    }

    function prefetchCommentCounts(items: Post[]): void {
      if (!isBrowser) {
        return;
      }
      void commentsFacade.prefetchCounts(items);
    }

    function bootstrapUserOptions(): void {
      if (!isBrowser) {
        return;
      }
      usersLookup
        .ensureUsersLoaded()
        .pipe(takeUntilDestroyed(destroyRef))
        .subscribe({
          error: (err) => {
            console.error('Failed to load users for filters:', err);
            notifications.showHttpError(err, i18n.translate('users.loadListError'));
          },
        });
    }

    function syncPaginationOnFilterChange(): void {
      let previous: PostFilters | null = null;
      effect(() => {
        const filters = filtersService.filters();
        if (previous && previous.title === filters.title && previous.userId === filters.userId) {
          return;
        }
        if (previous) {
          patchState(store, { page: pagination.defaultPage });
          requestDebouncedListReload();
        }
        previous = filters;
      });
    }
  }),
) satisfies Type<PostsService>;

import { inject, Injectable } from '@angular/core';
import { catchError, map, of, type Observable } from 'rxjs';

import { PostsApiService } from '@/app/shared/data-access/posts/posts-api.service';
import { UsersApiService } from '@/app/shared/data-access/users/users-api.service';
import { I18nService } from '@/app/shared/i18n/i18n.service';
import type { Post } from '@/app/shared/models/post';
import type { User } from '@/app/shared/models/user';
import { NotificationsService } from '@/app/shared/services/notifications/notifications.service';

@Injectable({ providedIn: 'root' })
export class UsersFacadeService {
  private readonly usersApi = inject(UsersApiService);
  private readonly postsApi = inject(PostsApiService);
  private readonly notifications = inject(NotificationsService);
  private readonly i18n = inject(I18nService);

  loadUserById(id: number, errorMessage?: string): Observable<User | null> {
    const resolvedErrorMessage = errorMessage ?? this.i18n.translate('userDetail.unableToLoadUser');
    return this.usersApi.getById(id).pipe(
      catchError((err) => {
        this.notifications.showHttpError(err, resolvedErrorMessage);
        return of(null as User | null);
      }),
    );
  }

  loadPostsForUser(userId: number, perPage: number, errorMessage?: string): Observable<Post[]> {
    const resolvedErrorMessage =
      errorMessage ?? this.i18n.translate('userDetail.unableToLoadPosts');
    return this.postsApi.list({ userId, perPage }).pipe(
      map((result) => result?.items ?? []),
      catchError((err) => {
        this.notifications.showHttpError(err, resolvedErrorMessage);
        return of<Post[]>([]);
      }),
    );
  }
}

import { isPlatformBrowser } from '@angular/common';
import { inject, computed, Type, DestroyRef, effect, PLATFORM_ID, signal } from '@angular/core';
import { takeUntilDestroyed, toObservable } from '@angular/core/rxjs-interop';
import { ActivatedRoute, Router } from '@angular/router';
import { signalStore, withState, withMethods, withComputed, patchState } from '@ngrx/signals';
import { EMPTY, catchError, combineLatest, distinctUntilChanged, switchMap, tap } from 'rxjs';

import { AuthService } from '@/app/core/auth/auth-service/auth.service';
import {
  DEFAULT_PAGINATION_CONFIG,
  PAGINATION_CONFIG,
  type PaginationConfig,
} from '@/app/shared/config/pagination.config';
import { UsersApiService } from '@/app/shared/data-access/users/users-api.service';
import { I18nService } from '@/app/shared/i18n/i18n.service';
import type { PaginationMeta } from '@/app/shared/models/pagination';
import type { User } from '@/app/shared/models/user';
import { NotificationsService } from '@/app/shared/services/notifications/notifications.service';
import { mapHttpError } from '@/app/shared/utils/error-mapper';
import { normalizePage, findNearestOption } from '@/app/shared/utils/pagination-utils';

import type { SortField, UsersService } from './users.service';

interface SortState {
  field: SortField;
  dir: 1 | -1;
}

interface UsersState {
  ids: number[];
  entities: Record<number, User>;
  pagination: PaginationMeta | null;
  loading: boolean;
  error: string | null;
  deletingId: number | null;
  searchTerm: string;
  sortState: SortState;
  page: number;
  perPage: number;
  perPageOptions: readonly number[];
}

interface LoadUsersOptions {
  page?: number;
  perPage?: number;
  searchTerm?: string;
  pushUrl?: boolean;
}

interface UsersLoadCriteria {
  page: number;
  perPage: number;
  searchTerm: string;
  pushUrl: boolean;
  reload: number;
}

export const UsersStoreAdapter = signalStore(
  withState<UsersState>({
    ids: [],
    entities: {},
    pagination: null,
    loading: true,
    error: null,
    deletingId: null,
    searchTerm: '',
    sortState: { field: 'name', dir: 1 },
    page: DEFAULT_PAGINATION_CONFIG.defaultPage,
    perPage: DEFAULT_PAGINATION_CONFIG.defaultPerPage,
    perPageOptions: DEFAULT_PAGINATION_CONFIG.perPageOptions,
  }),

  withComputed((store) => ({
    users: computed(() => {
      const { field, dir } = store.sortState();
      const entities = store.entities();

      const getValue = (u: User) => {
        const v = u[field];
        const s = typeof v === 'string' ? v : String(v ?? '');
        return s.toLowerCase();
      };

      return store
        .ids()
        .map((id) => entities[id])
        .filter(Boolean)
        .sort((a, b) => {
          const av = getValue(a);
          const bv = getValue(b);
          if (av < bv) return -1 * dir;
          if (av > bv) return 1 * dir;
          return 0;
        });
    }),
  })),

  withMethods((store) => {
    const usersApi = inject(UsersApiService);
    const destroyRef = inject(DestroyRef);
    const router = inject(Router);
    const route = inject(ActivatedRoute);
    const platformId = inject(PLATFORM_ID);
    const auth = inject(AuthService);
    const notifications = inject(NotificationsService);
    const i18n = inject(I18nService);
    const pagination =
      inject<PaginationConfig | null>(PAGINATION_CONFIG, { optional: true }) ??
      DEFAULT_PAGINATION_CONFIG;
    const isBrowser = isPlatformBrowser(platformId);
    let bootstrapped = false;
    let reloadToken = 0;
    const criteriaSignal = signal<UsersLoadCriteria | null>(null);

    patchState(store, {
      page: pagination.defaultPage,
      perPage: pagination.defaultPerPage,
      perPageOptions: pagination.perPageOptions,
    });

    const ensurePerPage = (value: number | undefined): number => {
      const normalized = normalizePage(value, pagination.defaultPerPage);
      const options = store.perPageOptions();
      return findNearestOption(normalized, options, pagination.defaultPerPage);
    };

    const ensurePage = (value: number | undefined): number =>
      normalizePage(value, pagination.defaultPage);

    const loadUsers = (options: LoadUsersOptions = {}) => {
      const pushUrl = options.pushUrl ?? true;
      const currentPerPage = ensurePerPage(store.perPage());
      const targetPerPage = ensurePerPage(options.perPage ?? currentPerPage);
      const targetPage = ensurePage(options.page ?? store.page());
      const term = (options.searchTerm ?? store.searchTerm()).trim();

      const currentCriteria = criteriaSignal();
      const sameCriteria =
        currentCriteria !== null &&
        currentCriteria.page === targetPage &&
        currentCriteria.perPage === targetPerPage &&
        currentCriteria.searchTerm === term;

      if (sameCriteria && !store.error()) {
        return;
      }

      criteriaSignal.set({
        page: targetPage,
        perPage: targetPerPage,
        searchTerm: term,
        pushUrl,
        reload: sameCriteria ? ++reloadToken : reloadToken,
      });
    };

    const syncUrl = (criteria: UsersLoadCriteria, meta: PaginationMeta) => {
      if (!criteria.pushUrl) return;
      router
        .navigate([], {
          relativeTo: route,
          queryParams: {
            page: meta.page,
            per_page: meta.limit,
            search: criteria.searchTerm || null,
          },
          queryParamsHandling: 'merge',
          replaceUrl: true,
        })
        .catch(() => {});
    };

    const handleFetchSuccess = (
      items: User[],
      paginationMeta: PaginationMeta | null,
      criteria: UsersLoadCriteria,
    ) => {
      const userList = items ?? [];
      const entities = userList.reduce<Record<number, User>>((acc, user) => {
        acc[user.id] = user;
        return acc;
      }, {});
      const ids = userList.map((user) => user.id);

      patchState(store, {
        ids,
        entities,
        pagination: paginationMeta,
        loading: false,
        page: paginationMeta?.page ?? criteria.page,
        perPage: paginationMeta?.limit ?? criteria.perPage,
      });

      if (paginationMeta) {
        syncUrl(criteria, paginationMeta);
      }
    };

    const initializeUsersStream = () => {
      if (!isBrowser) {
        patchState(store, { loading: false });
        return;
      }

      combineLatest([toObservable(criteriaSignal), toObservable(auth.token)])
        .pipe(
          distinctUntilChanged(
            (
              [prevCriteria, prevToken]: [UsersLoadCriteria | null, string | null | undefined],
              [nextCriteria, nextToken]: [UsersLoadCriteria | null, string | null | undefined],
            ) => {
              const prevAuth = prevToken?.trim() ?? '';
              const nextAuth = nextToken?.trim() ?? '';
              if (prevAuth !== nextAuth) return false;

              if (!prevCriteria || !nextCriteria) return prevCriteria === nextCriteria;

              return (
                prevCriteria.page === nextCriteria.page &&
                prevCriteria.perPage === nextCriteria.perPage &&
                prevCriteria.searchTerm === nextCriteria.searchTerm &&
                prevCriteria.pushUrl === nextCriteria.pushUrl &&
                prevCriteria.reload === nextCriteria.reload
              );
            },
          ),
          switchMap(([criteria, token]) => {
            if (!criteria) {
              return EMPTY;
            }

            const normalizedToken = token?.trim() ?? '';
            if (!normalizedToken) {
              patchState(store, {
                loading: false,
                error: null,
                searchTerm: criteria.searchTerm,
                ids: [],
                entities: {},
                pagination: null,
              });
              return EMPTY;
            }

            patchState(store, {
              loading: true,
              error: null,
              searchTerm: criteria.searchTerm,
              page: criteria.page,
              perPage: criteria.perPage,
              ids: [],
              entities: {},
              pagination: null,
            });

            const params: {
              page: number;
              perPage: number;
              name?: string;
              email?: string;
            } = {
              page: criteria.page,
              perPage: criteria.perPage,
            };

            const term = criteria.searchTerm || '';
            if (term) {
              params.name = term;
              if (term.includes('@')) {
                params.email = term;
              }
            }

            return usersApi.list(params, { cache: true }).pipe(
              tap(({ items, pagination }) => {
                const list = items ?? [];
                const resolvedLimit = Math.max(1, pagination?.limit ?? criteria.perPage);
                const resolvedTotal = pagination?.total ?? list.length;
                const resolvedPages =
                  pagination?.pages ??
                  (resolvedTotal ? Math.ceil(Math.max(resolvedTotal, 1) / resolvedLimit) : 1);

                const normalizedLimit = ensurePerPage(resolvedLimit);
                const pages = Math.max(1, resolvedPages);

                if (resolvedTotal > 0 && criteria.page > pages) {
                  criteriaSignal.set({
                    ...criteria,
                    page: pages,
                    perPage: normalizedLimit,
                    pushUrl: true,
                    reload: ++reloadToken,
                  });
                  return;
                }

                const resolvedPage = Math.min(
                  Math.max(1, pagination?.page ?? criteria.page),
                  pages,
                );

                const meta: PaginationMeta = {
                  total: resolvedTotal,
                  pages,
                  page: resolvedPage,
                  limit: normalizedLimit,
                };

                handleFetchSuccess(list, meta, criteria);
              }),
              catchError((err) => {
                console.error('Failed to load users:', err);
                patchState(store, {
                  loading: false,
                  error: i18n.translate(mapHttpError(err).messageKey),
                });
                return EMPTY;
              }),
            );
          }),
          takeUntilDestroyed(destroyRef),
        )
        .subscribe();
    };

    const setupInitialState = () => {
      const qp = route.snapshot.queryParamMap;
      const rawPage = qp.get('page');
      const rawPerPage = qp.get('per_page');
      const rawSearch = qp.get('search');

      const parsedPage = Number(rawPage);
      const parsedPerPage = Number(rawPerPage);

      const initialPage = ensurePage(parsedPage);
      const initialPerPage = ensurePerPage(parsedPerPage);
      const initialSearch = (rawSearch ?? '').trim();

      const needsUrlFix =
        (rawPage !== null &&
          (!Number.isFinite(parsedPage) || initialPage !== Math.floor(parsedPage))) ||
        (rawPerPage !== null &&
          (!Number.isFinite(parsedPerPage) || initialPerPage !== Math.floor(parsedPerPage))) ||
        (rawSearch !== null && rawSearch !== initialSearch);

      loadUsers({
        page: initialPage,
        perPage: initialPerPage,
        searchTerm: initialSearch,
        pushUrl: needsUrlFix,
      });
    };

    const initializeBootstrap = () => {
      if (!isBrowser) {
        patchState(store, { loading: false });
        return;
      }

      const attempt = () => {
        if (bootstrapped) {
          return;
        }
        const token = auth.token();
        if (!token?.trim()) {
          return;
        }
        bootstrapped = true;
        setupInitialState();
      };

      attempt();

      effect(() => {
        const token = auth.token();
        if (token?.trim()) {
          attempt();
        } else if (bootstrapped) {
          bootstrapped = false;
          criteriaSignal.set(null);
          patchState(store, {
            ids: [],
            entities: {},
            pagination: null,
            loading: false,
            error: null,
            deletingId: null,
          });
        }
      });
    };

    const updateStatus = (userId: number, status: 'active' | 'inactive') => {
      const entities = store.entities();
      const existing = entities[userId];
      if (!existing) {
        return;
      }

      const original = { ...existing };
      const optimistic = { ...original, status };

      patchState(store, {
        entities: {
          ...entities,
          [userId]: optimistic,
        },
      });

      usersApi
        .update(userId, { status })
        .pipe(takeUntilDestroyed(destroyRef))
        .subscribe({
          next: (updatedUser) => {
            patchState(store, {
              entities: {
                ...store.entities(),
                [userId]: updatedUser,
              },
            });
          },
          error: (err) => {
            console.error('Failed to update user status:', err);
            patchState(store, {
              entities: {
                ...store.entities(),
                [userId]: original,
              },
            });
            notifications.showError(i18n.translate('userDetail.unableToUpdateStatusRetry'));
          },
        });
    };

    initializeUsersStream();
    initializeBootstrap();

    return {
      loadUsers,
      updateStatus,
      setDeleting(userId: number | null) {
        patchState(store, { deletingId: userId });
      },
      onSearch: (value: string) => {
        const sanitizedTerm = typeof value === 'string' ? value.trim() : '';
        if (sanitizedTerm === store.searchTerm().trim()) {
          return;
        }
        loadUsers({
          page: pagination.defaultPage,
          perPage: store.perPage(),
          searchTerm: sanitizedTerm,
          pushUrl: true,
        });
      },
      toggleSort: (field: SortField) => {
        const current = store.sortState();
        if (current.field === field) {
          patchState(store, {
            sortState: { field, dir: current.dir === 1 ? -1 : 1 },
          });
        } else {
          patchState(store, { sortState: { field, dir: 1 } });
        }
      },
      setPage: (page: number) => {
        const nextPage = ensurePage(page);
        loadUsers({ page: nextPage, perPage: store.perPage(), pushUrl: true });
      },
      setPerPage: (perPage: number) => {
        const nextPerPage = ensurePerPage(perPage);
        loadUsers({ page: pagination.defaultPage, perPage: nextPerPage, pushUrl: true });
      },
    };
  }),
) satisfies Type<UsersService>;

