    overlayCoordinator.coordinate.and.callFake((key, dialogRef) => {
      overlays.activate({
        key,
        close: () => dialogRef.close(),
        blockGlobalControls: true,
      });
      return () => overlays.release(key);
    });

    dialog.open.and.callFake(
      () =>
        ({
          closed: closed$.asObservable() as Observable<DeleteConfirmData | undefined>,
          close: () => closed$.next(null),
        }) as DialogRef<DeleteConfirmData>,
    );

    usersApi.getById.and.returnValue(of({ id: 1, name: 'Alice', email: 'a@test.com' } as User));
    usersApi.delete.and.returnValue(of(void 0));

    TestBed.configureTestingModule({
      providers: [
        UsersUiService,
        { provide: Dialog, useValue: dialog },
        { provide: DialogOverlayCoordinator, useValue: overlayCoordinator },
        { provide: ResponsiveDialogService, useValue: dialogLayouts },
        { provide: NotificationsService, useValue: notifications },
        { provide: UsersApiService, useValue: usersApi },
        { provide: I18nService, useValue: { translate: (k: string) => k } },
        { provide: usersServiceInjectionToken, useValue: mockStore },
      ],
    });

    service = TestBed.inject(UsersUiService);
  });

  it('openCreateUserModal mostra successo e reload dopo chiusura', () => {
    service.openCreateUserModal();

    expect(dialog.open).toHaveBeenCalled();
    const openArgs = dialog.open.calls.mostRecent().args[1];
    expect(openArgs?.ariaLabel).toBe('users.create.ariaLabel');
    expect(overlays.activate).toHaveBeenCalledWith(jasmine.objectContaining({ key: 'user-form' }));
    expect(overlayCoordinator.coordinate).toHaveBeenCalledWith(
      'user-form',
      jasmine.objectContaining({ close: jasmine.any(Function) }),
    );

    closed$.next('success');

    expect(notifications.showSuccess).toHaveBeenCalledWith('users.create.success');
    expect(mockStore.loadUsers).toHaveBeenCalledWith({ pushUrl: false });
    expect(overlays.release).toHaveBeenCalledWith('user-form');
    expect(overlayCoordinator.coordinate).toHaveBeenCalledWith(
      'user-form',
      jasmine.objectContaining({ close: jasmine.any(Function) }),
    );
  });

  it('openEditUserModal carica utente, apre dialog e gestisce successo', () => {
    service.openEditUserModal(1);

    const config = dialog.open.calls.mostRecent().args[1] as { data?: { user?: User } };
    expect(usersApi.getById).toHaveBeenCalledWith(1);
    expect(config?.data?.user?.id).toBe(1);

    closed$.next('success');

    expect(notifications.showSuccess).toHaveBeenCalledWith('users.update.success');
    expect(mockStore.loadUsers).toHaveBeenCalledWith({ pushUrl: false });
    expect(overlays.release).toHaveBeenCalledWith('user-form');
    expect(overlayCoordinator.coordinate).toHaveBeenCalledWith(
      'user-form',
      jasmine.objectContaining({ close: jasmine.any(Function) }),
    );
  });

  it('confirmDelete chiama delete e refresha lo store', () => {
    service.confirmDelete({ id: 7, name: 'Bob' } as User);

    const latest = dialog.open.calls.mostRecent();
    const data = (latest.args[1] as { data?: DeleteConfirmData }).data!;
    expect(data.title).toBe('users.delete.title');
    const obs$ = (data.confirmAction as () => Observable<void>)();
    obs$.subscribe();

    expect(mockStore.setDeleting).toHaveBeenCalledWith(7);
    expect(usersApi.delete).toHaveBeenCalledWith(7);
    expect(notifications.showSuccess).toHaveBeenCalledWith('users.delete.success');
    expect(overlayCoordinator.coordinate).toHaveBeenCalledWith(
      'user-delete-confirm',
      jasmine.objectContaining({ close: jasmine.any(Function) }),
    );
  });

  it('openEditUserModal gestisce errore caricamento utente', () => {
    usersApi.getById.and.returnValue(throwError(() => ({ status: 500 })));
    service.openEditUserModal(2);
    expect(notifications.showHttpError).toHaveBeenCalled();
  });
});

import { Injectable } from '@angular/core';
import { Observable, of, forkJoin } from 'rxjs';
import { catchError, finalize, map, shareReplay, tap, take } from 'rxjs/operators';

import { PostsApiService } from '@app/shared/data-access/posts/posts-api.service';

import type { Comment } from '@/app/shared/models/post';

@Injectable({ providedIn: 'root' })
export class CommentsCacheService {
  private static readonly DEFAULT_TTL_MS = 2 * 60 * 1000;
  private static readonly MAX_CACHED_POSTS = 50;

  readonly commentsMap = new Map<number, Comment[]>();
  readonly inFlight = new Map<number, Observable<Comment[] | null>>();
  readonly countMap = new Map<number, number>();
  readonly countInFlight = new Map<number, Observable<number>>();
  private readonly commentsExpiry = new Map<number, number>();
  private readonly countExpiry = new Map<number, number>();
  private readonly accessOrder: number[] = [];

  constructor(private readonly postsApi: PostsApiService) {}

  /**
   * Fetch comments for a post, using cache and deduping in-flight requests.
   * Returns an observable that emits the comments array (or null on error).
   */
  fetchComments(postId: number): Observable<Comment[] | null> {
    const cached = this.commentsMap.get(postId);
    if (cached && !this.isExpired(this.commentsExpiry, postId)) {
      this.updateAccessOrder(postId);
      return of(cached);
    }

    this.evictPost(postId);

    const existing = this.inFlight.get(postId) as Observable<Comment[] | null> | undefined;
    if (existing) {
      return existing;
    }

    const obs = this.postsApi.listComments(postId).pipe(
      map((comments) => comments ?? []),
      tap((comments) => {
        this.commentsMap.set(postId, comments);
        this.countMap.set(postId, comments.length);
        this.setExpiry(this.commentsExpiry, postId);
        this.setExpiry(this.countExpiry, postId);
        this.updateAccessOrder(postId);
        this.evictLRU();
      }),
      catchError(() => of<Comment[] | null>(null)),
      finalize(() => this.inFlight.delete(postId)),
      shareReplay({ bufferSize: 1, refCount: true }),
    );

    this.inFlight.set(postId, obs);
    return obs;
  }

  fetchCommentCount(postId: number): Observable<number> {
    const cached = this.countMap.get(postId);
    if (cached !== undefined && !this.isExpired(this.countExpiry, postId)) {
      return of(cached);
    }

    this.countMap.delete(postId);
    this.countExpiry.delete(postId);

    const existing = this.countInFlight.get(postId);
    if (existing) {
      return existing;
    }

    const obs = this.postsApi.countComments(postId).pipe(
      catchError(() => of(0)),
      tap((count) => this.countMap.set(postId, count)),
      tap(() => this.setExpiry(this.countExpiry, postId)),
      finalize(() => this.countInFlight.delete(postId)),
      shareReplay({ bufferSize: 1, refCount: true }),
    );

    this.countInFlight.set(postId, obs);
    return obs;
  }

  prefetchCounts(postIds: number[]): Observable<Record<number, number>> {
    if (postIds.length === 0) {
      return of({});
    }

    const tasks = postIds.map((id) =>
      this.fetchCommentCount(id).pipe(
        take(1),
        map((count) => ({ id, count })),
      ),
    );

    return forkJoin(tasks).pipe(
      map((results) =>
        results.reduce(
          (acc, curr) => ({ ...acc, [curr.id]: curr.count }),
          {} as Record<number, number>,
        ),
      ),
    );
  }

  setComments(postId: number, comments: Comment[]): void {
    this.commentsMap.set(postId, comments);
    this.countMap.set(postId, comments.length);
    this.setExpiry(this.commentsExpiry, postId);
    this.setExpiry(this.countExpiry, postId);
    this.updateAccessOrder(postId);
    this.evictLRU();
  }

  adjustCount(postId: number, delta: number): void {
    const current = this.countMap.get(postId) ?? this.commentsMap.get(postId)?.length ?? 0;
    const next = Math.max(0, current + delta);
    this.countMap.set(postId, next);
    if (next === 0) {
      this.countExpiry.delete(postId);
    } else {
      this.setExpiry(this.countExpiry, postId);
    }
  }

  getCachedComments(postId: number): Comment[] | undefined {
    return this.commentsMap.get(postId);
  }

  getCachedCount(postId: number): number | undefined {
    if (this.countMap.has(postId)) {
      return this.countMap.get(postId);
    }
    const c = this.commentsMap.get(postId);
    return c ? c.length : undefined;
  }

  hasFreshCount(postId: number): boolean {
    const cached = this.countMap.get(postId);
    if (cached === undefined) {
      return false;
    }

    const expiresAt = this.countExpiry.get(postId);
    if (!expiresAt) {
      return false;
    }

    if (Date.now() > expiresAt) {
      this.countExpiry.delete(postId);
      this.countMap.delete(postId);
      return false;
    }

    return true;
  }

  clear(postId?: number): void {
    if (postId === undefined) {
      this.commentsMap.clear();
      this.inFlight.clear();
      this.countMap.clear();
      this.countInFlight.clear();
      this.commentsExpiry.clear();
      this.countExpiry.clear();
      this.accessOrder.length = 0;
      return;
    }
    this.commentsMap.delete(postId);
    this.inFlight.delete(postId);
    this.countMap.delete(postId);
    this.countInFlight.delete(postId);
    this.commentsExpiry.delete(postId);
    this.countExpiry.delete(postId);
    const index = this.accessOrder.indexOf(postId);
    if (index > -1) {
      this.accessOrder.splice(index, 1);
    }
  }

  private setExpiry(
    store: Map<number, number>,
    postId: number,
    ttl = CommentsCacheService.DEFAULT_TTL_MS,
  ) {
    store.set(postId, Date.now() + ttl);
  }

  private isExpired(store: Map<number, number>, postId: number): boolean {
    const expiresAt = store.get(postId);
    if (!expiresAt) {
      return false;
    }
    if (Date.now() > expiresAt) {
      store.delete(postId);
      return true;
    }
    return false;
  }

  private evictPost(postId: number): void {
    this.commentsMap.delete(postId);
    this.inFlight.delete(postId);
    this.commentsExpiry.delete(postId);
    const index = this.accessOrder.indexOf(postId);
    if (index > -1) {
      this.accessOrder.splice(index, 1);
    }
  }

  /**
   * Updates the access order for LRU tracking.
   * Moves the postId to the end of the access order array (most recently used).
   */
  private updateAccessOrder(postId: number): void {
    const index = this.accessOrder.indexOf(postId);
    if (index > -1) {
      this.accessOrder.splice(index, 1);
    }
    this.accessOrder.push(postId);
  }

  /**
   * Evicts the least recently used entries if cache size exceeds MAX_CACHED_POSTS.
   */
  private evictLRU(): void {
    while (this.commentsMap.size > CommentsCacheService.MAX_CACHED_POSTS) {
      const oldest = this.accessOrder.shift();
      if (oldest !== undefined) {
        this.commentsMap.delete(oldest);
        this.commentsExpiry.delete(oldest);
        this.countMap.delete(oldest);
        this.countExpiry.delete(oldest);
      }
    }
  }
}

import { HttpClient, HttpParams } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { map, type Observable } from 'rxjs';

import {
  type CommentDto,
  type CreateCommentDto,
  type CreatePostDto,
  type PostDto,
  type UpdateCommentDto,
  type UpdatePostDto,
  mapCommentDto,
  mapCommentsDto,
  mapCreateCommentToDto,
  mapCreatePostToDto,
  mapPostDto,
  mapUpdateCommentToDto,
  mapUpdatePostToDto,
} from '@/app/shared/models/dto/post.dto';
import type { ListResponse } from '@/app/shared/models/list-response';
import { mapPaginatedResponse } from '@/app/shared/models/list-response.util';
import type {
  Post,
  Comment,
  CreatePost,
  CreateComment,
  UpdatePost,
  UpdateComment,
} from '@/app/shared/models/post';

@Injectable({ providedIn: 'root' })
export class PostsApiService {
  private readonly http = inject(HttpClient);
  private readonly base = '/posts';

  list(
    params: {
      page?: number;
      perPage?: number;
      userId?: number;
      title?: string;
    } = {},
  ): Observable<ListResponse<Post>> {
    let httpParams = new HttpParams();
    const { page, perPage, userId, title } = params;
    if (page) httpParams = httpParams.set('page', String(page));
    if (perPage) httpParams = httpParams.set('per_page', String(perPage));
    if (userId) httpParams = httpParams.set('user_id', String(userId));
    if (title) httpParams = httpParams.set('title', title);
    return this.http
      .get<PostDto[]>(this.base, { params: httpParams, observe: 'response' })
      .pipe(map((resp) => mapPaginatedResponse(resp, mapPostDto)));
  }

  getById(id: number): Observable<Post> {
    return this.http.get<PostDto>(`${this.base}/${id}`).pipe(map(mapPostDto));
  }

  create(payload: CreatePost): Observable<Post> {
    const dto: CreatePostDto = mapCreatePostToDto(payload);
    return this.http.post<PostDto>(this.base, dto).pipe(map(mapPostDto));
  }

  update(id: number, payload: UpdatePost): Observable<Post> {
    const dto: UpdatePostDto = mapUpdatePostToDto(payload);
    return this.http.patch<PostDto>(`${this.base}/${id}`, dto).pipe(map(mapPostDto));
  }

  delete(id: number): Observable<void> {
    return this.http.delete<void>(`${this.base}/${id}`);
  }

  listComments(postId: number): Observable<Comment[]> {
    return this.http
      .get<CommentDto[]>(`${this.base}/${postId}/comments`)
      .pipe(map((res) => mapCommentsDto(res)));
  }

  countComments(postId: number): Observable<number> {
    const params = new HttpParams().set('per_page', '1');
    return this.http
      .get<CommentDto[]>(`${this.base}/${postId}/comments`, { params, observe: 'response' })
      .pipe(
        map((resp) => {
          const header = Number(resp.headers.get('X-Pagination-Total'));
          if (Number.isFinite(header) && header >= 0) {
            return header;
          }
          return resp.body?.length ?? 0;
        }),
      );
  }

  createComment(postId: number, payload: CreateComment): Observable<Comment> {
    const dto: CreateCommentDto = mapCreateCommentToDto(postId, payload);
    return this.http
      .post<CommentDto>(`${this.base}/${postId}/comments`, dto)
      .pipe(map(mapCommentDto));
  }

  updateComment(commentId: number, payload: UpdateComment): Observable<Comment> {
    const dto: UpdateCommentDto = mapUpdateCommentToDto(payload);
    return this.http.patch<CommentDto>(`/comments/${commentId}`, dto).pipe(map(mapCommentDto));
  }

  deleteComment(commentId: number): Observable<void> {
    return this.http.delete<void>(`/comments/${commentId}`);
  }
}

import { HttpClient, HttpParams } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { map, shareReplay, tap, type Observable } from 'rxjs';

import {
  type CreateUserDto,
  type UpdateUserDto,
  type UserDto,
  mapCreateUserToDto,
  mapUpdateUserToDto,
  mapUserDto,
} from '@/app/shared/models/dto/user.dto';
import type { ListResponse } from '@/app/shared/models/list-response';
import { mapPaginatedResponse } from '@/app/shared/models/list-response.util';
import type { User, CreateUser, UpdateUser } from '@/app/shared/models/user';

@Injectable({ providedIn: 'root' })
export class UsersApiService {
  private readonly http = inject(HttpClient);
  private readonly base = '/users';
  private readonly listCache = new Map<string, Observable<ListResponse<User>>>();

  list(
    params: {
      page?: number;
      perPage?: number;
      name?: string;
      email?: string;
    } = {},
    options?: { cache?: boolean },
  ): Observable<ListResponse<User>> {
    let httpParams = new HttpParams();
    const { page, perPage, name, email } = params;
    if (page) httpParams = httpParams.set('page', String(page));
    if (perPage) httpParams = httpParams.set('per_page', String(perPage));
    if (name) httpParams = httpParams.set('name', name);
    if (email) httpParams = httpParams.set('email', email);

    const cacheKey = options?.cache ? this.getCacheKey(httpParams) : null;
    if (cacheKey) {
      const cached = this.listCache.get(cacheKey);
      if (cached) {
        return cached;
      }
    }

    const request$ = this.http
      .get<UserDto[]>(this.base, { params: httpParams, observe: 'response' })
      .pipe(
        map((resp) => mapPaginatedResponse(resp, mapUserDto)),
        tap({
          error: () => {
            if (cacheKey) {
              this.listCache.delete(cacheKey);
            }
          },
        }),
        shareReplay({ bufferSize: 1, refCount: false }),
      );

    if (cacheKey) {
      this.listCache.set(cacheKey, request$);
    }

    return request$;
  }

  getById(id: number): Observable<User> {
    return this.http.get<UserDto>(`${this.base}/${id}`).pipe(map(mapUserDto));
  }

  create(payload: CreateUser): Observable<User> {
    const dto: CreateUserDto = mapCreateUserToDto(payload);
    return this.http.post<UserDto>(this.base, dto).pipe(
      map(mapUserDto),
      tap(() => this.listCache.clear()),
    );
  }

  update(id: number, payload: UpdateUser): Observable<User> {
    const dto: UpdateUserDto = mapUpdateUserToDto(payload);
    return this.http.patch<UserDto>(`${this.base}/${id}`, dto).pipe(
      map(mapUserDto),
      tap(() => this.listCache.clear()),
    );
  }

  delete(id: number): Observable<void> {
    return this.http.delete<void>(`${this.base}/${id}`).pipe(tap(() => this.listCache.clear()));
  }

  private getCacheKey(params: HttpParams): string {
    const entries = params
      .keys()
      .sort((a, b) => a.localeCompare(b))
      .map((key) => `${key}=${params.getAll(key)?.join(',') ?? ''}`);
    return entries.join('&');
  }
}

