    }
  }
}

import { DOCUMENT, isPlatformBrowser } from '@angular/common';
import { effect, inject, Injectable, PLATFORM_ID, signal } from '@angular/core';

import en from '../../../assets/i18n/en.json';
import it from '../../../assets/i18n/it.json';

export type Locale = 'en' | 'it';

type Translations = Record<string, unknown>;

const TRANSLATIONS: Record<Locale, Translations> = {
  en,
  it,
};

const LANGUAGE_STORAGE_KEY = 'app-language';
const AVAILABLE_LOCALES: readonly Locale[] = ['en', 'it'];

@Injectable({ providedIn: 'root' })
export class I18nService {
  private readonly platformId = inject(PLATFORM_ID);
  private readonly document = inject(DOCUMENT);
  private readonly localeSignal = signal<Locale>(this.resolveInitialLocale());

  readonly locale = this.localeSignal.asReadonly();
  readonly availableLocales = AVAILABLE_LOCALES;

  constructor() {
    effect(() => {
      const value = this.localeSignal();
      if (isPlatformBrowser(this.platformId)) {
        try {
          localStorage.setItem(LANGUAGE_STORAGE_KEY, value);
        } catch {
          // ignore storage failures
        }
        this.document.documentElement.lang = value;
      }
    });
  }

  translate(key: string, params?: Record<string, string | number>): string {
    if (!key) {
      return '';
    }
    const locale = this.localeSignal();
    const dictionary = TRANSLATIONS[locale] ?? {};
    const value = key.split('.').reduce<unknown>((acc, token) => {
      if (acc && typeof acc === 'object' && token in acc) {
        return (acc as Record<string, unknown>)[token];
      }
      return undefined;
    }, dictionary);

    if (typeof value !== 'string') {
      return key;
    }

    if (!params) {
      return value;
    }

    return Object.entries(params).reduce((acc, [paramKey, paramValue]) => {
      return acc.replace(new RegExp(`{{\\s*${paramKey}\\s*}}`, 'g'), String(paramValue));
    }, value);
  }

  setLocale(locale: Locale): void {
    if (locale === this.localeSignal()) {
      return;
    }
    this.localeSignal.set(locale);
  }

  private resolveInitialLocale(): Locale {
    if (!isPlatformBrowser(this.platformId)) {
      return 'en';
    }
    try {
      const stored = localStorage.getItem(LANGUAGE_STORAGE_KEY) as Locale | null;
      if (stored && AVAILABLE_LOCALES.includes(stored)) {
        return stored;
      }
    } catch {
      // ignore
    }
    const navigatorLang = typeof navigator !== 'undefined' ? navigator.language.slice(0, 2) : 'en';
    return AVAILABLE_LOCALES.includes(navigatorLang as Locale) ? (navigatorLang as Locale) : 'en';
  }
}

import { BreakpointObserver } from '@angular/cdk/layout';
import { DOCUMENT, NgOptimizedImage, isPlatformBrowser } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  DestroyRef,
  OnInit,
  ViewChild,
  computed,
  inject,
  signal,
  PLATFORM_ID,
  ViewEncapsulation,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { MatIconModule } from '@angular/material/icon';
import { MatMenuModule, MatMenuTrigger } from '@angular/material/menu';
import { MatToolbarModule } from '@angular/material/toolbar';
import { NavigationEnd, Router, RouterModule } from '@angular/router';
import { LucideAngularModule, Menu } from 'lucide-angular';
import { filter } from 'rxjs';

import { LanguageSwitcherComponent } from '@app/shared/i18n/language-switcher.component';
import { TranslatePipe } from '@app/shared/i18n/translate.pipe';
import { LucideMatIconService } from '@app/shared/icons/lucide-mat-icon.service';
import { ButtonComponent } from '@app/shared/ui/button/button.component';

import { AuthService } from '@/app/core/auth/auth-service/auth.service';

import { AppearanceSwitcherComponent } from '../appearance-switcher/appearance-switcher.component';

@Component({
  selector: 'app-navbar',
  imports: [
    RouterModule,
    NgOptimizedImage,
    AppearanceSwitcherComponent,
    LanguageSwitcherComponent,
    TranslatePipe,
    MatToolbarModule,
    ButtonComponent,
    MatIconModule,
    MatMenuModule,
    LucideAngularModule,
  ],
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'banner',
    '[attr.data-menu-open]': 'menuOpen() ? "true" : "false"',
  },
})
export class Navbar implements OnInit {
  private readonly router = inject(Router);
  private readonly auth = inject(AuthService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly breakpointObserver = inject(BreakpointObserver);
  private readonly document = inject(DOCUMENT);
  private readonly platformId = inject(PLATFORM_ID);
  private readonly isBrowser = isPlatformBrowser(this.platformId);
  private readonly _lucideIcons = inject(LucideMatIconService);

  @ViewChild(MatMenuTrigger) private readonly menuTrigger?: MatMenuTrigger;

  readonly currentUrl = signal(this.router.url || '/');
  readonly isLoginRoute = computed(() => this.currentUrl().startsWith('/login'));
  readonly isMobile = signal(false);
  readonly isLogged = computed(() => this.auth.token() !== null);
  readonly menuOpen = signal(false);
  readonly Menu = Menu;

  ngOnInit(): void {
    this.breakpointObserver
      .observe('(max-width: 62rem)')
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(({ matches }) => this.isMobile.set(matches));

    this.syncBodyClass(this.isLoginRoute());

    this.router.events
      .pipe(
        filter((event): event is NavigationEnd => event instanceof NavigationEnd),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe((event) => {
        this.currentUrl.set(event.urlAfterRedirects || '/');
        this.syncBodyClass(this.isLoginRoute());
        this.closeMenu();
      });
  }

  isRouteActive(path: string): boolean {
    const current = this.currentUrl();
    if (path === '/') return current === '/' || current === '';
    return current === path || current.startsWith(`${path}/`) || current.startsWith(`${path}?`);
  }

  ariaCurrent(path: string): 'page' | null {
    return this.isRouteActive(path) ? 'page' : null;
  }

  logout(): void {
    this.auth.logout();
    this.router.navigate(['/login']).catch(() => {});
  }

  onMenuOpened(): void {
    this.menuOpen.set(true);
  }

  onMenuClosed(): void {
    this.menuOpen.set(false);
  }

  closeMenu(): void {
    this.menuTrigger?.closeMenu();
    this.menuOpen.set(false);
  }

  private syncBodyClass(isLogin: boolean): void {
    if (!this.isBrowser) return;
    const doc = this.document as Document | null;
    if (!doc || !doc.body) return;
    doc.body.classList.toggle('login-route', isLogin);
  }
}

import type {
  Comment,
  CreateComment,
  CreatePost,
  Post,
  UpdateComment,
  UpdatePost,
} from '@/app/shared/models/post';

export interface PostDto {
  id: number;
  user_id: number;
  title: string;
  body: string;
}

export type CreatePostDto = Omit<PostDto, 'id'>;
export type UpdatePostDto = Partial<CreatePostDto>;

export interface CommentDto {
  id: number;
  post_id: number;
  name: string;
  email: string;
  body: string;
}

export type CreateCommentDto = Omit<CommentDto, 'id'>;
export type UpdateCommentDto = Partial<Omit<CommentDto, 'id'>>;

export const mapPostDto = (dto: PostDto): Post => ({ ...dto });
export const mapPostsDto = (list: PostDto[] | null | undefined): Post[] =>
  (list ?? []).map((dto) => mapPostDto(dto));

export const mapCommentDto = (dto: CommentDto): Comment => ({ ...dto });
export const mapCommentsDto = (list: CommentDto[] | null | undefined): Comment[] =>
  (list ?? []).map((dto) => mapCommentDto(dto));

export const mapCreatePostToDto = (payload: CreatePost): CreatePostDto => ({
  user_id: payload.user_id,
  title: payload.title?.trim() ?? '',
  body: payload.body?.trim() ?? '',
});

export const mapUpdatePostToDto = (payload: UpdatePost): UpdatePostDto => ({
  ...payload,
  title: typeof payload.title === 'string' ? payload.title.trim() : undefined,
  body: typeof payload.body === 'string' ? payload.body.trim() : undefined,
});

export const mapCreateCommentToDto = (
  postId: number,
  payload: CreateComment,
): CreateCommentDto => ({
  post_id: postId,
  name: payload.name?.trim() ?? '',
  email: payload.email?.trim().toLowerCase() ?? '',
  body: payload.body?.trim() ?? '',
});

export const mapUpdateCommentToDto = (payload: UpdateComment): UpdateCommentDto => ({
  ...payload,
  body: typeof payload.body === 'string' ? payload.body.trim() : undefined,
});

import type { CreateUser, UpdateUser, User } from '@/app/shared/models/user';

export interface UserDto {
  id: number;
  name: string;
  email: string;
  gender?: string | null;
  status: 'active' | 'inactive';
}

export type CreateUserDto = Omit<UserDto, 'id'>;
export type UpdateUserDto = Partial<CreateUserDto>;

export const mapUserDto = (dto: UserDto): User => ({
  id: dto.id,
  name: dto.name?.trim() ?? '',
  email: dto.email?.trim() ?? '',
  gender: dto.gender ?? undefined,
  status: dto.status,
});

export const mapUsersDto = (list: UserDto[] | null | undefined): User[] =>
  (list ?? []).map((dto) => mapUserDto(dto));

export const mapCreateUserToDto = (payload: CreateUser): CreateUserDto => ({
  name: String(payload.name ?? '').trim(),
  email: String(payload.email ?? '')
    .trim()
    .toLowerCase(),
  gender: payload.gender ?? 'male',
  status: payload.status ?? 'active',
});

export const mapUpdateUserToDto = (payload: UpdateUser): UpdateUserDto => ({
  ...payload,
  name: typeof payload.name === 'string' ? payload.name.trim() : undefined,
  email: typeof payload.email === 'string' ? payload.email.trim().toLowerCase() : undefined,
});

import { isPlatformBrowser } from '@angular/common';
import { Injectable, PLATFORM_ID, inject, signal } from '@angular/core';
import { firstValueFrom, of, take } from 'rxjs';

import { CommentsCacheService } from '@/app/shared/data-access/comments/comments-cache.service';
import { PostsApiService } from '@/app/shared/data-access/posts/posts-api.service';
import { I18nService } from '@/app/shared/i18n/i18n.service';
import type { Comment, CreateComment, UpdateComment } from '@/app/shared/models/post';
import { NotificationsService } from '@/app/shared/services/notifications/notifications.service';

@Injectable({ providedIn: 'root' })
export class CommentsFacadeService {
  private static readonly PREFETCH_DEBOUNCE_MS = 150;

  private readonly postsApi = inject(PostsApiService);
  private readonly cache = inject(CommentsCacheService);
  private readonly notifications = inject(NotificationsService);
  private readonly i18n = inject(I18nService);
  private readonly platformId = inject(PLATFORM_ID);
  private readonly isBrowser = isPlatformBrowser(this.platformId);

  private readonly commentsSignal = signal<Partial<Record<number, Comment[]>>>({});
  private readonly loadingSignal = signal<Partial<Record<number, boolean>>>({});
  private readonly countsSignal = signal<Partial<Record<number, number>>>({});
  private lastPrefetchKey: string | null = null;
  private lastPrefetchAt = 0;

  comments(): Partial<Record<number, Comment[]>> {
    return this.commentsSignal();
  }

  loading(): Partial<Record<number, boolean>> {
    return this.loadingSignal();
  }

  counts(): Partial<Record<number, number>> {
    return this.countsSignal();
  }

  commentsFor(postId: number): Comment[] {
    return this.commentsSignal()[postId] ?? [];
  }

  isLoaded(postId: number): boolean {
    return Object.hasOwn(this.commentsSignal(), postId);
  }

  isLoading(postId: number): boolean {
    return Boolean(this.loadingSignal()[postId]);
  }

  toggleComments(postId: number, options?: { errorMessage?: string }): void {
    if (!this.isBrowser) {
      return;
    }

    if (this.isLoading(postId) || this.isLoaded(postId)) {
      return;
    }

    const errorMessage =
      options?.errorMessage ?? this.i18n.translate('userDetail.unableToLoadComments');

    this.loadingSignal.update((state) => ({ ...state, [postId]: true }));
    this.cache
      .fetchComments(postId)
      .pipe(take(1))
      .subscribe({
        next: (comments) => {
          const list = comments ?? [];
          this.commentsSignal.update((state) => ({ ...state, [postId]: list }));
          this.countsSignal.update((state) => ({
            ...state,
            [postId]: list.length,
          }));
          this.cache.setComments(postId, list);
        },
        error: (err: unknown) => {
          console.error('Failed to load comments', err);
          this.notifications.showHttpError(err, errorMessage);
          this.loadingSignal.update((state) => ({ ...state, [postId]: false }));
        },
        complete: () => {
          this.loadingSignal.update((state) => ({ ...state, [postId]: false }));
        },
      });
  }

  async prefetchCounts(posts: { id: number }[]): Promise<void> {
    if (!this.isBrowser || !posts.length) {
      return;
    }

    const ids = Array.from(
      new Set(posts.map((p) => p.id).filter((id) => Number.isFinite(id) && id > 0)),
    ).sort((a, b) => a - b);

    const idsToFetch = ids.filter((id) => !this.cache.hasFreshCount(id));
    if (!idsToFetch.length) {
      return;
    }

    const now = Date.now();
    const key = idsToFetch.join(',');
    if (
      key &&
      this.lastPrefetchKey === key &&
      now - this.lastPrefetchAt < CommentsFacadeService.PREFETCH_DEBOUNCE_MS
    ) {
      return;
    }

    this.lastPrefetchKey = key;
    this.lastPrefetchAt = now;
    try {
      const counts = await firstValueFrom(this.cache.prefetchCounts(idsToFetch));
      if (counts) {
        this.countsSignal.update((state) => ({ ...state, ...counts }));
      }
    } catch (err: unknown) {
      console.error('Failed to prefetch comment counts', err);
    }
  }

  createComment(postId: number, payload: CreateComment) {
    if (!this.isBrowser) return of(null as unknown as Comment);
    return this.postsApi.createComment(postId, payload).pipe(take(1));
  }

  updateComment(commentId: number, payload: UpdateComment) {
    if (!this.isBrowser) return of(null as unknown as Comment);
    return this.postsApi.updateComment(commentId, payload).pipe(take(1));
  }

  deleteComment(commentId: number) {
    if (!this.isBrowser) return of(void 0);
    return this.postsApi.deleteComment(commentId).pipe(take(1));
  }

  applyCreated(postId: number, comment: Comment): void {
    this.commentsSignal.update((state) => {
      const current = state[postId] ?? [];
      return { ...state, [postId]: [comment, ...current] };
    });
    this.countsSignal.update((state) => ({
      ...state,
      [postId]: (state[postId] ?? 0) + 1,
    }));
    this.cache.setComments(postId, this.commentsSignal()[postId] ?? []);
  }

  applyUpdated(postId: number, comment: Comment): void {
    this.commentsSignal.update((state) => {
      const current = state[postId];
      if (!current) return state;
      const next = current.map((c) => (c.id === comment.id ? comment : c));
      return { ...state, [postId]: next };
    });
    this.cache.setComments(postId, this.commentsSignal()[postId] ?? []);
  }

  applyDeleted(postId: number, commentId: number): void {
    this.commentsSignal.update((state) => {
      const current = state[postId];
      if (!current) return state;
      const filtered = current.filter((c) => c.id !== commentId);
      return { ...state, [postId]: filtered };
    });
    this.countsSignal.update((state) => ({
      ...state,
      [postId]: Math.max(0, (state[postId] ?? this.commentsSignal()[postId]?.length ?? 0) - 1),
    }));
    this.cache.setComments(postId, this.commentsSignal()[postId] ?? []);
  }
}

import { DialogConfig, DialogRef } from '@angular/cdk/dialog';
import { BreakpointObserver } from '@angular/cdk/layout';
import { Injectable, inject } from '@angular/core';

const MOBILE_QUERY = '(max-width: 639.98px)';

export type DialogPanelVariant = 'sm' | 'md' | 'lg' | 'sheet' | 'fullscreen';

type ResponsiveDialogConfig<TData, R, C> = DialogConfig<TData, DialogRef<R, C>>;

export interface ResponsiveDialogOptions<TData = unknown, R = unknown, C = unknown> {
  ariaLabel: string;
  data?: TData;
  shared?: Partial<ResponsiveDialogConfig<TData, R, C>>;
  desktop?: Partial<ResponsiveDialogConfig<TData, R, C>>;
  mobile?: Partial<ResponsiveDialogConfig<TData, R, C>>;
  panelVariant?: DialogPanelVariant;
  desktopPanelVariant?: DialogPanelVariant;
  mobilePanelVariant?: DialogPanelVariant;
}

@Injectable({ providedIn: 'root' })
export class ResponsiveDialogService {
  private readonly breakpointObserver = inject(BreakpointObserver);

  form<TData, R = unknown, C = unknown>(
    options: ResponsiveDialogOptions<TData, R, C>,
  ): ResponsiveDialogConfig<TData, R, C> {
    const sharedDefaults: ResponsiveDialogConfig<TData, R, C> = {
      ariaLabel: options.ariaLabel,
      backdropClass: 'app-dialog-overlay',
      autoFocus: true,
      restoreFocus: true,
      closeOnNavigation: true,
      disableClose: false,
    };

    const sharedConfig = this.mergeConfig(sharedDefaults, options.shared);
    const desktopVariant = options.desktopPanelVariant ?? options.panelVariant ?? 'md';
    const mobileVariant = options.mobilePanelVariant ?? options.panelVariant ?? 'sheet';

    const desktopBase: ResponsiveDialogConfig<TData, R, C> = {
      ...sharedConfig,
      width: '37.5rem',
      maxWidth: '90vw',
      panelClass: this.combinePanelClasses(
        sharedConfig.panelClass,
        'app-dialog-panel',
        this.variantClass(desktopVariant),
        this.sizeClass(desktopVariant),
      ),
    };
    const desktopConfig = this.mergeConfig(desktopBase, options.desktop);

    const mobileBase: ResponsiveDialogConfig<TData, R, C> = {
      ...sharedConfig,
      width: '100vw',
      maxWidth: '100vw',
      maxHeight: undefined,
      panelClass: this.combinePanelClasses(
        sharedConfig.panelClass,
        'app-dialog-panel',
        this.variantClass(mobileVariant),
        this.sizeClass(mobileVariant),
      ),
    };
    const mobileConfig = this.mergeConfig(mobileBase, options.mobile);

    if (options.data !== undefined) {
      desktopConfig.data = options.data;
      mobileConfig.data = options.data;
    }

    return this.breakpointObserver.isMatched(MOBILE_QUERY) ? mobileConfig : desktopConfig;
  }

  private mergeConfig<TData, R, C>(
    base: ResponsiveDialogConfig<TData, R, C>,
    override?: Partial<ResponsiveDialogConfig<TData, R, C>>,
  ): ResponsiveDialogConfig<TData, R, C> {
    if (!override) {
      return { ...base };
    }

    const merged: ResponsiveDialogConfig<TData, R, C> = { ...base, ...override };
    merged.panelClass = this.combinePanelClasses(base.panelClass, override?.panelClass);
    return merged;
  }

  private combinePanelClasses(
    ...classes: Array<string | string[] | undefined>
  ): string | string[] | undefined {
    const flattened = classes
      .flatMap((value) => {
        if (Array.isArray(value)) {
          return value;
        }
        return value ? [value] : [];
      })
      .filter((value, index, all) => all.indexOf(value) === index);

    if (!flattened.length) {
      return undefined;
    }

    return flattened.length === 1 ? flattened[0] : flattened;
  }

  private variantClass(variant?: DialogPanelVariant): string | undefined {
    return variant ? `app-dialog--${variant}` : undefined;
  }

  private sizeClass(variant?: DialogPanelVariant): string | undefined {
    return variant ? `app-dialog-size-${variant}` : undefined;
  }
}

import { Injectable } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class IdService {
  readonly counters = new Map<string, number>();

  /**
   * Return a deterministic incremental id scoped by prefix.
   * Example: id('search') -> 'search-1', 'search-2', ...
   */
  next(prefix = 'id'): string {
    const current = this.counters.get(prefix) ?? 0;
    const next = current + 1;
    this.counters.set(prefix, next);
    return `${prefix}-${next}`;
  }

  /**
   * Reset counters (useful in tests)
   */
  reset(prefix?: string): void {
    if (prefix) {
      this.counters.delete(prefix);
    } else {
      this.counters.clear();
    }
  }
}

import { DOCUMENT } from '@angular/common';
import { PLATFORM_ID } from '@angular/core';
import { TestBed, fakeAsync, flush } from '@angular/core/testing';

import { ThemeService } from './theme.service';

class StorageStub {
  private readonly store = new Map<string, string>();

  getItem(key: string): string | null {
    return this.store.get(key) ?? null;
  }

  setItem(key: string, value: string): void {
    this.store.set(key, value);
  }

  removeItem(key: string): void {
    this.store.delete(key);
  }

  clear(): void {
    this.store.clear();
  }
}

class MockMediaQueryList implements MediaQueryList {
  matches = true;
  media = '(prefers-color-scheme: light)';
  onchange: ((this: MediaQueryList, ev: MediaQueryListEvent) => void) | null = null;

  private listener?: (event: MediaQueryListEvent) => void;

  addEventListener(type: string, listener: EventListenerOrEventListenerObject): void {
    if (type !== 'change') {
      return;
    }
    this.listener =
      typeof listener === 'function' ? listener : (event) => listener.handleEvent(event);
  }

  removeEventListener(type: string): void {
    if (type === 'change') {
      this.listener = undefined;
    }
  }

  addListener(listener: (this: MediaQueryList, ev: MediaQueryListEvent) => void): void {
    this.listener = (event) => listener.call(this, event);
  }

  removeListener(): void {
    this.listener = undefined;
  }

  dispatchEvent(event: Event): boolean {
    this.listener?.(event as MediaQueryListEvent);
    return true;
  }

  trigger(event: MediaQueryListEvent): void {
    this.listener?.(event);
  }
}

describe('ThemeService', () => {
  let service: ThemeService;
  let mockDocument: Document;
  let body: HTMLBodyElement;
  let docElement: HTMLElement;
  let storage: StorageStub;
  let matchMediaSpy: jasmine.Spy<(query: string) => MediaQueryList>;
  let mediaQueryList: MockMediaQueryList;
  const originalMatchMedia = globalThis.matchMedia ?? null;

  beforeEach(() => {
    storage = new StorageStub();
    spyOn(localStorage, 'getItem').and.callFake((key: string) => storage.getItem(key));
    spyOn(localStorage, 'setItem').and.callFake((key: string, value: string) => {
      storage.setItem(key, value);
    });
    spyOn(localStorage, 'removeItem').and.callFake((key: string) => storage.removeItem(key));
    spyOn(localStorage, 'clear').and.callFake(() => storage.clear());

    mockDocument = document.implementation.createHTMLDocument('theme-spec');
    body = mockDocument.body as HTMLBodyElement;
    docElement = mockDocument.documentElement;
    body.className = '';
    delete docElement.dataset.theme;

    mediaQueryList = new MockMediaQueryList();
    matchMediaSpy = jasmine.createSpy('matchMedia').and.returnValue(mediaQueryList);
    (globalThis as typeof globalThis & { matchMedia: typeof matchMediaSpy }).matchMedia =
      matchMediaSpy;

    TestBed.configureTestingModule({
      providers: [
        ThemeService,
        { provide: PLATFORM_ID, useValue: 'browser' },
        { provide: DOCUMENT, useValue: mockDocument },
      ],
    });
  });

  afterEach(() => {
    (
      globalThis as typeof globalThis & { matchMedia?: (query: string) => MediaQueryList }
    ).matchMedia = originalMatchMedia ?? undefined;
  });

  it('should toggle theme from system preference to dark and persist it', (done) => {
    service = TestBed.inject(ThemeService);
    service.setPreference('system');
    (localStorage.setItem as jasmine.Spy).calls.reset();

    service.toggleTheme();

    setTimeout(() => {
      expect(service.theme()).toBe('dark');
      expect(body.classList.contains('dark-theme')).toBeTrue();
      expect(localStorage.setItem).toHaveBeenCalledWith('preferred-theme', 'dark');
      done();
    }, 10);
  });

  it('should set preference to light and update DOM dataset', (done) => {
    service = TestBed.inject(ThemeService);
    service.setPreference('dark');
    service.setPreference('light');

    setTimeout(() => {
      expect(service.theme()).toBe('light');
      expect(body.classList.contains('light-theme')).toBeTrue();
      expect(docElement.dataset.theme).toBe('light');
      done();
    }, 10);
  });

  it('should toggle reading mode and store flag', (done) => {
    service = TestBed.inject(ThemeService);
    service.setReadingMode(false);
    (localStorage.setItem as jasmine.Spy).calls.reset();

    service.toggleReadingMode();

    setTimeout(() => {
      expect(service.isReadingMode()).toBeTrue();
      expect(body.classList.contains('reading-mode')).toBeTrue();
      expect(localStorage.setItem).toHaveBeenCalledWith('reading-mode', 'true');
      service.toggleReadingMode();
      setTimeout(() => {
        expect(service.isReadingMode()).toBeFalse();
        expect(body.classList.contains('reading-mode')).toBeFalse();
        expect(localStorage.setItem).toHaveBeenCalledWith('reading-mode', 'false');
        done();
      }, 10);
    }, 10);
  });

  it('should respond to system theme changes via matchMedia listener', () => {
    service = TestBed.inject(ThemeService);
    service.setPreference('system');

    mediaQueryList.trigger({ matches: false } as MediaQueryListEvent);

    expect(service.theme()).toBe('dark');
    expect(matchMediaSpy).toHaveBeenCalled();
  });

  it('does not crash when localStorage.setItem throws (Safari private mode)', fakeAsync(() => {
    (localStorage.setItem as jasmine.Spy).and.callFake(() => {
      throw new Error('blocked');
    });

    expect(() => {
      service = TestBed.inject(ThemeService);
    }).not.toThrow();

    expect(() => {
      service.setPreference('light');
    }).not.toThrow();

    flush();
    expect(body.classList.contains('light-theme')).toBeTrue();
  }));
});

import { DOCUMENT, isPlatformBrowser } from '@angular/common';
import {
  DestroyRef,
  computed,
  effect,
  inject,
  Injectable,
  PLATFORM_ID,
  signal,
} from '@angular/core';

type ThemeName = 'light' | 'dark';
export type ThemePreference = ThemeName | 'system';

const STORAGE_KEY = 'preferred-theme';
const READING_STORAGE_KEY = 'reading-mode';

@Injectable({ providedIn: 'root' })
export class ThemeService {
  private readonly platformId = inject(PLATFORM_ID);
  private readonly document = inject(DOCUMENT);
  private readonly destroyRef = inject(DestroyRef);
  private readonly preferenceSignal = signal<ThemePreference>(this.resolveInitialPreference());
  private readonly systemThemeSignal = signal<ThemeName>(this.detectSystemTheme());
  private readonly readingModeSignal = signal<boolean>(this.resolveInitialReadingMode());

  private readonly appliedTheme = computed<ThemeName>(() =>
    this.preferenceSignal() === 'system'
      ? this.systemThemeSignal()
      : (this.preferenceSignal() as ThemeName),
  );

  readonly theme = this.appliedTheme;
  readonly preference = this.preferenceSignal.asReadonly();
  readonly isLightTheme = computed(() => this.theme() === 'light');
  readonly isSystemPreference = computed(() => this.preferenceSignal() === 'system');
  readonly readingMode = this.readingModeSignal.asReadonly();
  readonly isReadingMode = computed(() => this.readingModeSignal());

  private readonly mediaQuery: MediaQueryList | null = null;

  constructor() {
    if (
      isPlatformBrowser(this.platformId) &&
      globalThis.window != null &&
      globalThis.matchMedia != null
    ) {
      this.mediaQuery = globalThis.matchMedia('(prefers-color-scheme: light)');

      const update = (event?: MediaQueryList | MediaQueryListEvent) => {
        const matches = event ? event.matches : (this.mediaQuery?.matches ?? false);
        this.systemThemeSignal.set(matches ? 'light' : 'dark');
      };

      update(this.mediaQuery ?? undefined);

      const listener = (event: MediaQueryListEvent) => update(event);

      type MQLWithLegacy = MediaQueryList & {
        addListener?: (l: (e: MediaQueryListEvent) => void) => void;
        removeListener?: (l?: (e: MediaQueryListEvent) => void) => void;
        addEventListener?: (t: string, l: unknown) => void;
        removeEventListener?: (t: string, l?: unknown) => void;
      };

      const mq = this.mediaQuery as MQLWithLegacy | null;

      if (mq?.addEventListener) {
        mq.addEventListener('change', listener);
        this.destroyRef.onDestroy(() => mq.removeEventListener?.('change', listener));
      } else {
        type LegacyAddFn = (listener: (ev: MediaQueryListEvent) => void) => void;
        type LegacyRemoveFn = (listener?: (ev: MediaQueryListEvent) => void) => void;
        const legacy = mq as unknown as Record<string, unknown>;
        const addLegacy = legacy['addListener'] as LegacyAddFn | undefined;
        addLegacy?.call(mq as MediaQueryList, listener);
        this.destroyRef.onDestroy(() =>
          (legacy['removeListener'] as LegacyRemoveFn | undefined)?.call(
            mq as MediaQueryList,
            listener,
          ),
        );
      }
    }

    effect(() => {
      const currentTheme = this.theme();
      const preference = this.preferenceSignal();
      const readingMode = this.readingModeSignal();

      if (!isPlatformBrowser(this.platformId)) {
        return;
      }

      const body = this.document.body;
      const docEl = this.document.documentElement;

      body.classList.toggle('light-theme', currentTheme === 'light');
      body.classList.toggle('dark-theme', currentTheme === 'dark');
      body.classList.toggle('reading-mode', readingMode);
      docEl.dataset.theme = currentTheme;

      try {
        localStorage.setItem(STORAGE_KEY, preference);
      } catch {
        // ignore storage failures (e.g. Safari private mode)
      }
      try {
        localStorage.setItem(READING_STORAGE_KEY, readingMode ? 'true' : 'false');
      } catch {
        // ignore storage failures (e.g. Safari private mode)
      }
    });
  }

  toggleTheme(): void {
    const preference = this.preferenceSignal();
    if (preference === 'system') {
      const next = this.systemThemeSignal() === 'light' ? 'dark' : 'light';
      this.preferenceSignal.set(next);
      return;
    }
    this.preferenceSignal.set(preference === 'light' ? 'dark' : 'light');
  }

  setTheme(theme: ThemeName): void {
    this.preferenceSignal.set(theme);
  }

  setPreference(preference: ThemePreference): void {
    this.preferenceSignal.set(preference);
  }

  toggleReadingMode(): void {
    this.setReadingMode(!this.readingModeSignal());
  }

  setReadingMode(enabled: boolean): void {
    this.readingModeSignal.set(enabled);
  }

  private detectSystemTheme(): ThemeName {
    if (
      !isPlatformBrowser(this.platformId) ||
      globalThis.window == null ||
      globalThis.matchMedia == null
    ) {
      return 'dark';
    }

    return globalThis.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark';
  }

  private resolveInitialPreference(): ThemePreference {
    if (!isPlatformBrowser(this.platformId)) {
      return 'system';
    }

    try {
      const stored = localStorage.getItem(STORAGE_KEY) as ThemePreference | null;
      if (stored === 'light' || stored === 'dark' || stored === 'system') {
        return stored;
      }
      return 'system';
    } catch {
      return 'system';
    }
  }

  private resolveInitialReadingMode(): boolean {
    if (!isPlatformBrowser(this.platformId)) {
      return false;
    }

    try {
      const stored = localStorage.getItem(READING_STORAGE_KEY);
      return stored === 'true';
    } catch {
      return false;
    }
  }
}

import { computed, inject, Injectable, signal } from '@angular/core';
import { catchError, map, of, shareReplay, tap, throwError, type Observable } from 'rxjs';

import { UsersApiService } from '@/app/shared/data-access/users/users-api.service';
import type { User } from '@/app/shared/models/user';

@Injectable({ providedIn: 'root' })
export class UsersLookupService {
  private readonly usersApi = inject(UsersApiService);
  private readonly cache = signal<User[]>([]);
  private readonly loading = signal(false);
  private readonly lastFetchedAt = signal<number | null>(null);
  private inFlight: Observable<User[]> | null = null;
  private readonly ttlMs = 5 * 60 * 1000;

  readonly users = computed(() => this.cache());
  readonly userLookup = computed(() =>
    this.cache().reduce<Record<number, User>>((acc, user) => {
      acc[user.id] = user;
      return acc;
    }, {}),
  );
  readonly isLoading = computed(() => this.loading());

  ensureUsersLoaded(options?: { force?: boolean; perPage?: number }): Observable<User[]> {
    if (!options?.force && this.cache().length && !this.isExpired()) {
      return of(this.cache());
    }

    if (this.inFlight) {
      return this.inFlight;
    }

    const perPage = options?.perPage ?? 50;
    this.loading.set(true);
    const request$ = this.usersApi.list({ perPage }, { cache: true }).pipe(
      map((resp) => resp.items ?? []),
      tap((list) => {
        this.mergeUsers(list);
        this.lastFetchedAt.set(Date.now());
        this.loading.set(false);
        this.inFlight = null;
      }),
      catchError((err: unknown) => {
        this.loading.set(false);
        this.inFlight = null;
        return throwError(() => err);
      }),
      shareReplay({ bufferSize: 1, refCount: false }),
    );

    this.inFlight = request$;
    return request$;
  }

  ensureUserInCache(id: number): Observable<User> {
    const existing = this.userLookup()[id];
    if (existing) {
      return of(existing);
    }
    this.loading.set(true);
    return this.usersApi.getById(id).pipe(
      tap((user) => {
        this.mergeUsers([user]);
        this.lastFetchedAt.set(Date.now());
        this.loading.set(false);
      }),
      catchError((err: unknown) => {
        this.loading.set(false);
        return throwError(() => err);
      }),
    );
  }

  seed(users: User[]): void {
    if (!users.length) return;
    this.mergeUsers(users);
  }

  clear(): void {
    this.cache.set([]);
    this.lastFetchedAt.set(null);
  }

  private mergeUsers(users: User[]): void {
    if (!users.length) {
      return;
    }
    const incoming = new Map<number, User>();
    for (const user of users) {
      incoming.set(user.id, user);
    }
    this.cache.update((current) => {
      const combined = new Map<number, User>();
      for (const user of current) {
        combined.set(user.id, user);
      }
      for (const user of incoming.values()) {
        combined.set(user.id, user);
      }
      return Array.from(combined.values());
    });
  }

  private isExpired(): boolean {
    const ts = this.lastFetchedAt();
    if (!ts) return true;
    return Date.now() - ts > this.ttlMs;
  }
}

