  });

  const configure = (page: number, pageCount: number) => {
    host.page = page;
    host.pageCount = pageCount;
    hostFixture.detectChanges();
  };

  it('emits an increased page when next is allowed', () => {
    configure(1, 3);
    const emitted: number[] = [];
    component.pageChange.subscribe((value) => emitted.push(value));

    component.next();
    expect(emitted).toEqual([2]);
  });

  it('does not emit when already at the limits', () => {
    configure(1, 1);
    const emitted: number[] = [];
    component.pageChange.subscribe((value) => emitted.push(value));

    component.prev();
    component.next();
    expect(emitted).toEqual([]);
  });

  it('caps values when the page is outside the configured range', () => {
    configure(5, 4);
    const emitted: number[] = [];
    component.pageChange.subscribe((value) => emitted.push(value));

    component.next();
    component.prev();
    expect(emitted).toEqual([4]);
  });
});

import { CommonModule } from '@angular/common';
import { ChangeDetectionStrategy, Component, computed, input, output } from '@angular/core';
import { MatIconModule } from '@angular/material/icon';

import { TranslatePipe } from '@app/shared/i18n/translate.pipe';
import { ButtonComponent } from '@app/shared/ui/button/button.component';

@Component({
  standalone: true,
  selector: 'app-pagination',
  templateUrl: './pagination.component.html',
  styleUrls: ['./pagination.component.scss'],
  imports: [CommonModule, MatIconModule, ButtonComponent, TranslatePipe],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PaginationComponent {
  readonly page = input.required<number>();
  readonly pageCount = input.required<number>();
  readonly ariaLabel = input<string>('');

  readonly pageChange = output<number>();

  protected readonly canPrev = computed(() => (this.page() ?? 1) > 1);
  protected readonly canNext = computed(() => (this.page() ?? 1) < (this.pageCount() ?? 1));

  prev(): void {
    if (!this.canPrev()) return;
    const nextPage = Math.max(1, (this.page() || 1) - 1);
    this.pageChange.emit(nextPage);
  }

  next(): void {
    if (!this.canNext()) return;
    const nextPage = Math.min(this.pageCount() || 1, (this.page() || 1) + 1);
    this.pageChange.emit(nextPage);
  }
}

