export type SelectVariant = 'default' | 'compact';
type SelectValue = string | number;
type SelectControl =
  | FormControl<string>
  | FormControl<number>
  | FormControl<string | null>
  | FormControl<number | null>;
type SelectOption = { value: SelectValue; label: string };

@Component({
  standalone: true,
  selector: 'app-select',
  templateUrl: './select.component.html',
  styleUrls: ['./select.component.scss'],
  imports: [ReactiveFormsModule, CommonModule, MatSelectModule, MatFormFieldModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class SelectComponent {
  readonly control = input<SelectControl | null>(null);
  readonly options = input<ReadonlyArray<SelectOption>>([]);
  readonly placeholder = input<string>('');
  readonly showPlaceholder = input<boolean>(true);
  readonly variant = input<SelectVariant>('default');
  readonly disabled = input(false);
  readonly required = input(false);
  readonly id = input<string>('');
  readonly label = input<string>('');
  readonly ariaLabel = input<string>('');
  readonly ariaDescribedBy = input<string>('');

  readonly selectionChange = output<string>();

  private readonly idService = inject(IdService);
  private readonly elementRef = inject(ElementRef);
  private readonly platformId = inject(PLATFORM_ID);
  private readonly documentRef = inject(DOCUMENT, { optional: true });
  private readonly isBrowser = isPlatformBrowser(this.platformId);
  protected readonly _fallbackId = this.idService.next('select');

  protected readonly resolvedId = computed(() => (this.id() ? this.id() : this._fallbackId));

  @HostBinding('class.select--in-modal')
  get isInModal(): boolean {
    if (!this.isBrowser) return false;
    const doc = this.documentRef;
    if (!doc) return false;
    let element: HTMLElement | null = this.elementRef.nativeElement as HTMLElement | null;
    while (element && element !== doc.body) {
      if (element.classList?.contains('cdk-overlay-pane')) {
        return true;
      }
      element = element.parentElement;
    }
    return false;
  }

  constructor() {
    effect(() => {
      const ctrl = this.control();
      const dis = this.disabled();
      if (ctrl) {
        if (dis) {
          ctrl.disable();
        } else {
          ctrl.enable();
        }
      }
    });
  }

  onSelectionChange(value: SelectValue): void {
    this.selectionChange.emit(String(value));
  }
}

import { HttpErrorResponse } from '@angular/common/http';

export type UiError =
  | { kind: 'unauthorized'; messageKey: string }
  | { kind: 'forbidden'; messageKey: string }
  | { kind: 'validation'; messageKey: string; details?: unknown }
  | { kind: 'rate-limit'; messageKey: string; retryAfterMs?: number }
  | { kind: 'network'; messageKey: string }
  | { kind: 'unknown'; messageKey: string };

export function mapHttpError(error: unknown): UiError {
  if (!(error instanceof HttpErrorResponse)) {
    return { kind: 'unknown', messageKey: 'common.errors.unknown' };
  }

  const { status } = error;

  if (status === 0) {
    return {
      kind: 'network',
      messageKey: 'common.errors.networkUnavailable',
    };
  }

  if (status === 401) {
    return {
      kind: 'unauthorized',
      messageKey: 'common.errors.sessionExpired',
    };
  }

  if (status === 403) {
    return {
      kind: 'forbidden',
      messageKey: 'common.errors.forbidden',
    };
  }

  if (status === 422) {
    return {
      kind: 'validation',
      messageKey: 'common.errors.validation',
      details: error.error,
    };
  }

  if (status === 429) {
    return {
      kind: 'rate-limit',
      messageKey: 'common.errors.rateLimit',
      retryAfterMs: parseRetryAfter(error.headers?.get('Retry-After')),
    };
  }

  return {
    kind: 'unknown',
    messageKey: 'common.errors.unexpected',
  };
}

function parseRetryAfter(value: string | null): number | undefined {
  if (!value) {
    return undefined;
  }

  const numeric = Number(value);
  if (Number.isFinite(numeric)) {
    return Math.max(0, numeric) * 1000;
  }

  const parsed = Date.parse(value);
  if (!Number.isNaN(parsed)) {
    const delta = parsed - Date.now();
    return delta > 0 ? delta : undefined;
  }

  return undefined;
}

import { join } from 'node:path';

import {
  AngularNodeAppEngine,
  createNodeRequestHandler,
  isMainModule,
  writeResponseToNodeResponse,
} from '@angular/ssr/node';
import express from 'express';

const browserDistFolder = join(import.meta.dirname, '../browser');

const app = express();
const angularApp = new AngularNodeAppEngine();

app.use(
  express.static(browserDistFolder, {
    maxAge: '1y',
    index: false,
    redirect: false,
  }),
);

app.use((req, res, next) => {
  angularApp
    .handle(req)
    .then((response) => (response ? writeResponseToNodeResponse(response, res) : next()))
    .catch(next);
});

if (isMainModule(import.meta.url)) {
  const port = process.env['PORT'] || 4000;
  app.listen(port, (error) => {
    if (error) {
      throw error;
    }

    console.info(`Node Express server listening on http://localhost:${port}`);
  });
}

export const reqHandler = createNodeRequestHandler(app);
